{
  "name": "WishLog",
  "description": "A clean, mobile-first wishlist manager to organize future purchases. Replaces chat notes with a structured, offline-capable list supporting bilingual (English/Telugu) usage."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  Gadgets = 'Gadgets',
  Home = 'Home',
  Travel = 'Travel',
  Courses = 'Courses',
  Others = 'Others'
}

export enum Priority {
  High = 'High',
  Medium = 'Medium',
  Low = 'Low'
}

export enum Status {
  Planned = 'Planned',
  Bought = 'Bought',
  Dropped = 'Dropped'
}

export interface WishlistItem {
  id: string;
  name: string;
  category: Category;
  price: number;
  priority: Priority;
  status: Status;
  notes?: string;
  createdAt: number;
  updatedAt: number;
}

export type SortField = 'price' | 'priority' | 'createdAt';
export type SortDirection = 'asc' | 'desc';

export interface FilterState {
  category: Category | 'All';
  priority: Priority | 'All';
  status: Status | 'All';
}

export type Language = 'en' | 'te';
export type Theme = 'light' | 'dark';

