export const LANG_KEY = 'wishlog_lang_v1';

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 text-white hover:bg-blue-700 focus:ring-blue-500 dark:bg-blue-500 dark:hover:bg-blue-600",
    secondary: "bg-gray-200 text-gray-900 hover:bg-gray-300 focus:ring-gray-500 dark:bg-gray-700 dark:text-gray-100 dark:hover:bg-gray-600",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500",
    ghost: "bg-transparent text-gray-600 hover:bg-gray-100 dark:text-gray-300 dark:hover:bg-gray-800"
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-4 py-2 text-base",
    lg: "px-6 py-3 text-lg"
  };

  const widthClass = fullWidth ? "w-full" : "";

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${widthClass} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, Language } from '../types';
import { TRANSLATIONS } from '../constants';
import { Button } from './ui/Button';
import { X } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
  lang: Language;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave, lang }) => {
  const t = TRANSLATIONS[lang];

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setNotes(initialData.notes || '');
    } else {
      // Reset form
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setNotes('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      name,
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      notes
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white dark:bg-gray-900 rounded-xl shadow-xl w-full max-w-md max-h-[90vh] overflow-y-auto flex flex-col">

        <div className="flex items-center justify-between p-4 border-b dark:border-gray-800">
          <h2 className="text-xl font-bold">{initialData ? t.editItem : t.addItem}</h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-4 space-y-4 flex-1">
          <div>
            <label className="block text-sm font-medium mb-1">{t.labels.name}</label>
            <input 
              type="text" 
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full p-2 rounded-lg border dark:border-gray-700 bg-transparent focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="e.g., Noise Cancelling Headphones"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">{t.labels.category}</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
                className="w-full p-2 rounded-lg border dark:border-gray-700 bg-transparent focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c} className="dark:bg-gray-900">{t.categories[c]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">{t.labels.price}</label>
              <input 
                type="number" 
                min="0"
                step="0.01"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                className="w-full p-2 rounded-lg border dark:border-gray-700 bg-transparent focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="0.00"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">{t.labels.priority}</label>
              <div className="flex flex-col gap-2">
                {(Object.values(Priority) as Priority[]).map((p) => (
                   <label key={p} className="flex items-center gap-2 cursor-pointer">
                     <input 
                      type="radio" 
                      name="priority"
                      checked={priority === p}
                      onChange={() => setPriority(p)}
                      className="text-blue-600 focus:ring-blue-500"
                     />
                     <span className="text-sm">{t.priorities[p]}</span>
                   </label>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">{t.labels.status}</label>
              <select 
                value={status}
                onChange={(e) => setStatus(e.target.value as Status)}
                className="w-full p-2 rounded-lg border dark:border-gray-700 bg-transparent focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {Object.values(Status).map(s => (
                  <option key={s} value={s} className="dark:bg-gray-900">{t.statuses[s]}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">{t.labels.notes}</label>
            <textarea 
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full p-2 rounded-lg border dark:border-gray-700 bg-transparent focus:ring-2 focus:ring-blue-500 outline-none resize-none"
            />
          </div>

          <div className="pt-4 flex gap-3">
             <Button type="button" variant="secondary" onClick={onClose} fullWidth>
              {t.labels.cancel}
             </Button>
             <Button type="submit" variant="primary" fullWidth>
              {t.labels.save}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React from 'react';
import { WishlistItem, Priority, Status, Language } from '../types';
import { TRANSLATIONS } from '../constants';
import { Edit2, Trash2, MoreVertical, Calendar } from 'lucide-react';

interface ItemCardProps {
  item: WishlistItem;
  onEdit: (item: WishlistItem) => void;
  onDelete: (id: string) => void;
  lang: Language;
}

export const ItemCard: React.FC<ItemCardProps> = ({ item, onEdit, onDelete, lang }) => {
  const t = TRANSLATIONS[lang];
  const [showMenu, setShowMenu] = React.useState(false);

  const priorityColors = {
    [Priority.High]: 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300',
    [Priority.Medium]: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-300',
    [Priority.Low]: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300',
  };

  const statusColors = {
    [Status.Planned]: 'bg-blue-50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300 border-blue-200 dark:border-blue-800',
    [Status.Bought]: 'bg-green-50 text-green-700 dark:bg-green-900/20 dark:text-green-300 border-green-200 dark:border-green-800',
    [Status.Dropped]: 'bg-gray-50 text-gray-600 dark:bg-gray-800 dark:text-gray-400 border-gray-200 dark:border-gray-700',
  };

  const formattedDate = new Date(item.createdAt).toLocaleDateString(lang === 'en' ? 'en-US' : 'te-IN', {
    month: 'short', day: 'numeric', year: 'numeric'
  });

  return (
    <div className={`relative p-4 rounded-xl border-l-4 shadow-sm bg-white dark:bg-gray-900 transition-all hover:shadow-md ${statusColors[item.status]}`}>

      <div className="flex justify-between items-start mb-2">
        <div>
           <span className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400">
             {t.categories[item.category]}
           </span>
           <h3 className="text-lg font-bold text-gray-900 dark:text-gray-100 break-words leading-tight">
             {item.name}
           </h3>
        </div>

        <div className="relative">
          <button 
            onClick={() => setShowMenu(!showMenu)} 
            className="p-1 rounded-full hover:bg-black/5 dark:hover:bg-white/10"
          >
            <MoreVertical size={18} />
          </button>

          {showMenu && (
            <>
              <div className="fixed inset-0 z-10" onClick={() => setShowMenu(false)} />
              <div className="absolute right-0 mt-2 w-32 bg-white dark:bg-gray-800 rounded-lg shadow-lg border dark:border-gray-700 z-20 py-1 overflow-hidden">
                <button 
                  onClick={() => { onEdit(item); setShowMenu(false); }}
                  className="w-full px-4 py-2 text-left text-sm flex items-center gap-2 hover:bg-gray-50 dark:hover:bg-gray-700"
                >
                  <Edit2 size={14} /> {t.labels.editItem}
                </button>
                <button 
                  onClick={() => { 
                    if(window.confirm(t.labels.confirmDelete)) {
                      onDelete(item.id); 
                    }
                    setShowMenu(false); 
                  }}
                  className="w-full px-4 py-2 text-left text-sm flex items-center gap-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20"
                >
                  <Trash2 size={14} /> {t.labels.delete}
                </button>
              </div>
            </>
          )}
        </div>
      </div>

      <div className="flex flex-wrap items-center gap-2 mt-3">
        <span className={`px-2 py-0.5 rounded-md text-xs font-medium ${priorityColors[item.priority]}`}>
          {t.priorities[item.priority]}
        </span>
        <span className="flex items-center gap-1 text-xs text-gray-500 dark:text-gray-400">
          <Calendar size={12} /> {formattedDate}
        </span>
      </div>

      {item.notes && (
        <p className="mt-2 text-sm text-gray-600 dark:text-gray-400 bg-black/5 dark:bg-white/5 p-2 rounded-md">
          {item.notes}
        </p>
      )}

      <div className="mt-3 pt-3 border-t border-black/5 dark:border-white/5 flex justify-between items-center">
         <span className="text-sm text-gray-500 dark:text-gray-400">{t.statuses[item.status]}</span>
         <span className="text-xl font-bold font-mono tracking-tight">
            {item.price.toLocaleString(lang === 'en' ? 'en-US' : 'te-IN', { style: 'currency', currency: 'INR' })}
         </span>
      </div>

    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  WishlistItem, 
  Category, 
  Priority, 
  Status, 
  FilterState, 
  SortField, 
  Language, 
  Theme 
} from './types';
import { TRANSLATIONS, STORAGE_KEY, THEME_KEY, LANG_KEY } from './constants';
import { ItemForm } from './components/ItemForm';
import { ItemCard } from './components/ItemCard';
import { Button } from './components/ui/Button';
import { 
  Plus, 
  Search, 
  Filter, 
  Download, 
  Languages, 
  Moon, 
  Sun,
  LayoutGrid,
  ListFilter
} from 'lucide-react';

const App: React.FC = () => {
  // --- State Management ---
  const [items, setItems] = useState<WishlistItem[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<WishlistItem | null>(null);

  // Settings
  const [lang, setLang] = useState<Language>('en');
  const [theme, setTheme] = useState<Theme>('light');

  // Filters & Search
  const [search, setSearch] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
    category: 'All',
    priority: 'All',
    status: 'All'
  });
  const [sortField, setSortField] = useState<SortField>('createdAt');

  const t = TRANSLATIONS[lang];

  // --- Effects ---

  // Load initial data
  useEffect(() => {
    const savedItems = localStorage.getItem(STORAGE_KEY);
    const savedTheme = localStorage.getItem(THEME_KEY) as Theme;
    const savedLang = localStorage.getItem(LANG_KEY) as Language;

    if (savedItems) setItems(JSON.parse(savedItems));
    if (savedTheme) setTheme(savedTheme);
    if (savedLang) setLang(savedLang);
    else {
      // Auto-detect browser language if not saved
      if (navigator.language.startsWith('te')) setLang('te');
    }
  }, []);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, theme);
    document.documentElement.className = theme;
  }, [theme]);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  // --- Handlers ---

  const handleSaveItem = (itemData: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => {
    const now = Date.now();
    if (editingItem) {
      setItems(prev => prev.map(item => 
        item.id === editingItem.id 
          ? { ...item, ...itemData, updatedAt: now } 
          : item
      ));
    } else {
      const newItem: WishlistItem = {
        ...itemData,
        id: crypto.randomUUID(),
        createdAt: now,
        updatedAt: now
      };
      setItems(prev => [newItem, ...prev]);
    }
    setEditingItem(null);
  };

  const handleDeleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const handleExport = () => {
    const headers = ['Name', 'Category', 'Price', 'Priority', 'Status', 'Notes', 'Created Date'];
    const csvContent = [
      headers.join(','),
      ...items.map(item => [
        `"${item.name.replace(/"/g, '""')}"`,
        item.category,
        item.price,
        item.priority,
        item.status,
        `"${(item.notes || '').replace(/"/g, '""')}"`,
        new Date(item.createdAt).toISOString().split('T')[0]
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `wishlog_export_${new Date().toISOString().slice(0,10)}.csv`;
    link.click();
  };

  const toggleLanguage = () => setLang(prev => prev === 'en' ? 'te' : 'en');
  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  // --- Derived State ---

  const filteredItems = useMemo(() => {
    return items
      .filter(item => {
        const matchesSearch = item.name.toLowerCase().includes(search.toLowerCase());
        const matchesCategory = filters.category === 'All' || item.category === filters.category;
        const matchesPriority = filters.priority === 'All' || item.priority === filters.priority;
        const matchesStatus = filters.status === 'All' || item.status === filters.status;
        return matchesSearch && matchesCategory && matchesPriority && matchesStatus;
      })
      .sort((a, b) => {
        if (sortField === 'price') return b.price - a.price; // Descending price
        if (sortField === 'priority') {
          const pMap = { [Priority.High]: 3, [Priority.Medium]: 2, [Priority.Low]: 1 };
          return pMap[b.priority] - pMap[a.priority];
        }
        return b.createdAt - a.createdAt; // Newest first default
      });
  }, [items, search, filters, sortField]);

  const stats = useMemo(() => {
    const total = filteredItems.reduce((acc, curr) => acc + curr.price, 0);
    return { count: filteredItems.length, total };
  }, [filteredItems]);

  return (
    <div className="min-h-screen pb-24">

      {/* --- Header --- */}
      <header className="sticky top-0 z-30 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md border-b dark:border-gray-800">
        <div className="max-w-3xl mx-auto px-4 py-3">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-blue-600 rounded-lg text-white">
                <LayoutGrid size={20} />
              </div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
                {t.appTitle}
              </h1>
            </div>
            <div className="flex gap-2">
              <button onClick={toggleLanguage} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800" title="Switch Language">
                <Languages size={20} />
                <span className="sr-only">Language</span>
              </button>
              <button onClick={toggleTheme} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800" title="Toggle Theme">
                {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
                <span className="sr-only">Theme</span>
              </button>
            </div>
          </div>

          <div className="flex gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="text"
                placeholder={t.searchPlaceholder}
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-10 pr-4 py-2 rounded-lg bg-gray-100 dark:bg-gray-800 focus:ring-2 focus:ring-blue-500 outline-none text-sm transition-all"
              />
            </div>
            <button 
              onClick={() => setShowFilters(!showFilters)}
              className={`p-2 rounded-lg border transition-colors ${showFilters ? 'bg-blue-50 border-blue-200 text-blue-600 dark:bg-blue-900/20 dark:border-blue-800 dark:text-blue-300' : 'border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-800'}`}
            >
              <ListFilter size={20} />
            </button>
          </div>

          {/* Collapsible Filters */}
          <div className={`overflow-hidden transition-all duration-300 ease-in-out ${showFilters ? 'max-h-60 opacity-100 mt-3' : 'max-h-0 opacity-0'}`}>
            <div className="grid grid-cols-2 gap-2 pb-1">
               <select 
                className="p-2 rounded-lg bg-gray-50 dark:bg-gray-800 text-sm border dark:border-gray-700"
                value={filters.category}
                onChange={(e) => setFilters({...filters, category: e.target.value as Category | 'All'})}
               >
                 <option value="All">{t.filters.all} {t.labels.category}</option>
                 {Object.values(Category).map(c => <option key={c} value={c}>{t.categories[c]}</option>)}
               </select>

               <select 
                className="p-2 rounded-lg bg-gray-50 dark:bg-gray-800 text-sm border dark:border-gray-700"
                value={filters.status}
                onChange={(e) => setFilters({...filters, status: e.target.value as Status | 'All'})}
               >
                 <option value="All">{t.filters.all} {t.labels.status}</option>
                 {Object.values(Status).map(s => <option key={s} value={s}>{t.statuses[s]}</option>)}
               </select>

               <select 
                className="p-2 rounded-lg bg-gray-50 dark:bg-gray-800 text-sm border dark:border-gray-700"
                value={sortField}
                onChange={(e) => setSortField(e.target.value as SortField)}
               >
                 <option value="createdAt">{t.filters.newest}</option>
                 <option value="price">{t.filters.priceHigh}</option>
                 <option value="priority">{t.filters.sortBy} {t.labels.priority}</option>
               </select>

               <Button size="sm" variant="ghost" onClick={handleExport} className="justify-center border dark:border-gray-700">
                  <Download size={14} className="mr-2" /> CSV
               </Button>
            </div>
          </div>
        </div>
      </header>

      {/* --- Stats Bar --- */}
      <div className="max-w-3xl mx-auto px-4 py-2">
        <div className="flex justify-between items-center text-sm text-gray-500 dark:text-gray-400">
           <span>{stats.count} {t.count}</span>
           <span>{t.total}: <span className="font-semibold text-gray-900 dark:text-gray-100">{stats.total.toLocaleString(lang === 'en' ? 'en-US' : 'te-IN', { style: 'currency', currency: 'INR' })}</span></span>
        </div>
      </div>

      {/* --- Main List --- */}
      <main className="max-w-3xl mx-auto px-4 py-2 space-y-4">
        {filteredItems.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-center opacity-60">
             <div className="w-20 h-20 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                <Filter size={32} className="text-gray-400" />
             </div>
             <p className="text-lg font-medium">{t.emptyState}</p>
          </div>
        ) : (
          filteredItems.map(item => (
            <ItemCard 
              key={item.id} 
              item={item} 
              onEdit={(i) => { setEditingItem(i); setIsFormOpen(true); }}
              onDelete={handleDeleteItem}
              lang={lang}
            />
          ))
        )}
      </main>

      {/* --- Floating Action Button --- */}
      <div className="fixed bottom-6 right-6 z-40">
        <button
          onClick={() => { setEditingItem(null); setIsFormOpen(true); }}
          className="bg-blue-600 hover:bg-blue-700 text-white w-14 h-14 rounded-full shadow-lg shadow-blue-600/30 flex items-center justify-center transition-transform hover:scale-105 active:scale-95 focus:outline-none focus:ring-4 focus:ring-blue-300 dark:focus:ring-blue-900"
          aria-label={t.addItem}
        >
          <Plus size={28} />
        </button>
      </div>

      {/* --- Modal --- */}
      <ItemForm 
        isOpen={isFormOpen} 
        onClose={() => setIsFormOpen(false)} 
        onSave={handleSaveItem}
        initialData={editingItem}
        lang={lang}
      />

    </div>
  );
};

export default App;

export enum Category {
  Gadgets = 'Gadgets',
  Home = 'Home',
  Travel = 'Travel',
  Courses = 'Courses',
  Personal = 'Personal',
  Others = 'Others'
}

export enum Priority {
  High = 'High',
  Medium = 'Medium',
  Low = 'Low'
}

export enum Status {
  Planned = 'Planned',
  Bought = 'Bought',
  Dropped = 'Dropped'
}

