import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, EcommercePlatform, Language } from '../types';
import { TRANSLATIONS } from '../constants';
import { Button } from './ui/Button';
import { X, Link as LinkIcon } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
  lang: Language;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave, lang }) => {
  const t = TRANSLATIONS[lang];

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [platform, setPlatform] = useState<EcommercePlatform>(EcommercePlatform.Amazon);
  const [notes, setNotes] = useState('');
  const [link, setLink] = useState('');

  useEffect(() => {
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setPlatform(initialData.platform || EcommercePlatform.Other);
      setNotes(initialData.notes || '');
      setLink(initialData.link || '');
    } else {
      // Reset form
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setPlatform(EcommercePlatform.Amazon);
      setNotes('');
      setLink('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      name,
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      platform,
      notes,
      link: link.trim()
