              placeholder="e.g., Noise Cancelling Headphones"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">{t.labels.category}</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
                className="w-full p-2 rounded-lg border dark:border-gray-700 bg-transparent focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c} className="dark:bg-gray-900">{t.categories[c]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">{t.labels.price}</label>
              <input 
                type="number" 
                min="0"
                step="0.01"
