                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">{t.labels.platform}</label>
              <select 
                value={platform}
                onChange={(e) => setPlatform(e.target.value as EcommercePlatform)}
                className="w-full p-2 rounded-lg border dark:border-gray-700 bg-transparent focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {Object.values(EcommercePlatform).map(p => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.platforms[p]}</option>
                ))}
