import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  WishlistItem, 
  Category, 
  Priority, 
  Status, 
  EcommercePlatform,
  FilterState, 
  SortField, 
  Language, 
  Theme 
} from './types';
import { TRANSLATIONS, STORAGE_KEY, THEME_KEY, LANG_KEY } from './constants';
import { ItemForm } from './components/ItemForm';
import { ItemCard } from './components/ItemCard';
import { ConfirmDialog } from './components/ConfirmDialog';
import { Button } from './components/ui/Button';
import { 
  Plus, 
  Search, 
  Filter, 
  Download, 
  Upload,
  Languages, 
  Moon, 
  Sun,
  LayoutGrid,
  ListFilter
} from 'lucide-react';

const App: React.FC = () => {
  // --- State Management ---
  const [items, setItems] = useState<WishlistItem[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<WishlistItem | null>(null);
  const [itemToDelete, setItemToDelete] = useState<string | null>(null);

  // Settings
  const [lang, setLang] = useState<Language>('en');
  const [theme, setTheme] = useState<Theme>('light');

  // Filters & Search
  const [search, setSearch] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
    category: 'All',
    priority: 'All',
    status: 'All'
  });
  const [sortField, setSortField] = useState<SortField>('createdAt');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const t = TRANSLATIONS[lang];

  // --- Effects ---

  // Load initial data
  useEffect(() => {
    const savedItems = localStorage.getItem(STORAGE_KEY);
    const savedTheme = localStorage.getItem(THEME_KEY) as Theme;
    const savedLang = localStorage.getItem(LANG_KEY) as Language;

    if (savedItems) setItems(JSON.parse(savedItems));
    if (savedTheme) setTheme(savedTheme);
    if (savedLang) setLang(savedLang);
    else {
      // Auto-detect browser language if not saved
      if (navigator.language.startsWith('te')) setLang('te');
    }
  }, []);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, theme);
    document.documentElement.className = theme;
  }, [theme]);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  // --- Handlers ---

  const handleSaveItem = (itemData: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => {
    const now = Date.now();
    if (editingItem) {
      setItems(prev => prev.map(item => 
        item.id === editingItem.id 
          ? { ...item, ...itemData, updatedAt: now } 
          : item
      ));
    } else {
      const newItem: WishlistItem = {
        ...itemData,
        id: crypto.randomUUID(),
        createdAt: now,
        updatedAt: now
      };
      setItems(prev => [newItem, ...prev]);
    }
    setEditingItem(null);
  };

  const initiateDelete = (id: string) => {
    setItemToDelete(id);
  };

  const confirmDelete = () => {
    if (itemToDelete) {
      setItems(prev => prev.filter(item => item.id !== itemToDelete));
      setItemToDelete(null);
    }
  };

  const handleExport = () => {
    const headers = ['Name', 'Category', 'Price', 'Priority', 'Status', 'Platform', 'Notes', 'Link', 'Created Date'];
    const csvContent = [
      headers.join(','),
      ...items.map(item => [
        `"${item.name.replace(/"/g, '""')}"`,
        item.category,
        item.price,
        item.priority,
        item.status,
        item.platform || EcommercePlatform.Other,
        `"${(item.notes || '').replace(/"/g, '""')}"`,
        `"${(item.link || '').replace(/"/g, '""')}"`,
        new Date(item.createdAt).toISOString().split('T')[0]
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `wishlog_export_${new Date().toISOString().slice(0,10)}.csv`;
    link.click();
  };

  const handleImportClick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.value = ''; // Reset input
      fileInputRef.current.click();
    }
  };

  const parseCSVLine = (text: string) => {
    const result = [];
    let curr = '';
    let inQuote = false;
    for (let i = 0; i < text.length; i++) {
        const char = text[i];
        if (char === '"') {
            if (inQuote && text[i+1] === '"') {
                curr += '"';
                i++;
            } else {
                inQuote = !inQuote;
            }
        } else if (char === ',' && !inQuote) {
            result.push(curr);
            curr = '';
        } else {
            curr += char;
        }
    }
    result.push(curr);
    return result;
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const lines = content.split(/\r?\n/).filter(line => line.trim() !== '');

        // Skip header row
        const dataLines = lines.slice(1);

        const newItems: WishlistItem[] = [];
        const now = Date.now();

        dataLines.forEach(line => {
          const cols = parseCSVLine(line);
          if (cols.length >= 5) { // Ensure minimum required fields exist
            let name, categoryStr, priceStr, priorityStr, statusStr, notes, link = '', platformStr = '', dateStr;

            // Backward Compatibility Logic
            if (cols.length === 9) {
                // Newest format with Platform
                [name, categoryStr, priceStr, priorityStr, statusStr, platformStr, notes, link, dateStr] = cols;
            } else if (cols.length === 8) {
                // Previous format (Name, Cat, Price, Prio, Stat, Notes, Link, Date)
                [name, categoryStr, priceStr, priorityStr, statusStr, notes, link, dateStr] = cols;
                platformStr = EcommercePlatform.Other;
            } else if (cols.length === 7) {
                // Oldest format (Name, Cat, Price, Prio, Stat, Notes, Date)
                [name, categoryStr, priceStr, priorityStr, statusStr, notes, dateStr] = cols;
                platformStr = EcommercePlatform.Other;
            } else {
                return; // Skip invalid lines
            }

            // Validate Enums
            const category = Object.values(Category).includes(categoryStr as Category) ? categoryStr as Category : Category.Others;
            const priority = Object.values(Priority).includes(priorityStr as Priority) ? priorityStr as Priority : Priority.Medium;
            const status = Object.values(Status).includes(statusStr as Status) ? statusStr as Status : Status.Planned;
            const platform = Object.values(EcommercePlatform).includes(platformStr as EcommercePlatform) ? platformStr as EcommercePlatform : EcommercePlatform.Other;
            const price = parseFloat(priceStr) || 0;

            const newItem: WishlistItem = {
              id: crypto.randomUUID(),
              name: name.trim(),
              category,
              price,
              priority,
              status,
              platform,
              notes: notes ? notes.trim() : '',
              link: link ? link.trim() : '',
              createdAt: dateStr ? new Date(dateStr).getTime() : now,
              updatedAt: now
            };
            newItems.push(newItem);
          }
        });

        if (newItems.length > 0) {
          setItems(prev => [...prev, ...newItems]);
          alert(t.importSuccess.replace('{count}', newItems.length.toString()));
          setShowFilters(false); // Close filters on success
        } else {
          alert(t.importError);
        }
      } catch (err) {
        console.error(err);
        alert(t.importError);
      }
    };
    reader.readAsText(file);
  };

  const toggleLanguage = () => setLang(prev => prev === 'en' ? 'te' : 'en');
  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  // --- Derived State ---

  const filteredItems = useMemo(() => {
    return items
      .filter(item => {
        const matchesSearch = item.name.toLowerCase().includes(search.toLowerCase());
        const matchesCategory = filters.category === 'All' || item.category === filters.category;
        const matchesPriority = filters.priority === 'All' || item.priority === filters.priority;
        const matchesStatus = filters.status === 'All' || item.status === filters.status;
        return matchesSearch && matchesCategory && matchesPriority && matchesStatus;
      })
      .sort((a, b) => {
        if (sortField === 'price') return b.price - a.price; // Descending price
        if (sortField === 'priority') {
          const pMap = { [Priority.High]: 3, [Priority.Medium]: 2, [Priority.Low]: 1 };
          return pMap[b.priority] - pMap[a.priority];
        }
        return b.createdAt - a.createdAt; // Newest first default
      });
  }, [items, search, filters, sortField]);

  const stats = useMemo(() => {
    const total = filteredItems.reduce((acc, curr) => acc + curr.price, 0);
    return { count: filteredItems.length, total };
  }, [filteredItems]);

  return (
    <div className="min-h-screen pb-24">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        accept=".csv" 
        className="hidden" 
      />

      {/* --- Header --- */}
      <header className="sticky top-0 z-30 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md border-b dark:border-gray-800">
        <div className="max-w-3xl mx-auto px-4 py-3">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-blue-600 rounded-lg text-white">
                <LayoutGrid size={20} />
              </div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
                {t.appTitle}
              </h1>
            </div>
            <div className="flex gap-2">
              <button onClick={toggleLanguage} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800" title="Switch Language">
                <Languages size={20} />
                <span className="sr-only">Language</span>
              </button>
              <button onClick={toggleTheme} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800" title="Toggle Theme">
                {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
                <span className="sr-only">Theme</span>
              </button>
            </div>
          </div>

          <div className="flex gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="text"
                placeholder={t.searchPlaceholder}
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-10 pr-4 py-2 rounded-lg bg-gray-100 dark:bg-gray-800 focus:ring-2 focus:ring-blue-500 outline-none text-sm transition-all"
              />
            </div>
            <button 
              onClick={() => setShowFilters(!showFilters)}
              className={`p-2 rounded-lg border transition-colors ${showFilters ? 'bg-blue-50 border-blue-200 text-blue-600 dark:bg-blue-900/20 dark:border-blue-800 dark:text-blue-300' : 'border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-800'}`}
            >
              <ListFilter size={20} />
            </button>
          </div>

          {/* Collapsible Filters */}
          <div className={`overflow-hidden transition-all duration-300 ease-in-out ${showFilters ? 'max-h-80 opacity-100 mt-3' : 'max-h-0 opacity-0'}`}>
            <div className="grid grid-cols-2 gap-2 pb-1">
               <select 
                className="p-2 rounded-lg bg-gray-50 dark:bg-gray-800 text-sm border dark:border-gray-700"
                value={filters.category}
                onChange={(e) => setFilters({...filters, category: e.target.value as Category | 'All'})}
               >
                 <option value="All">{t.filters.all} {t.labels.category}</option>
                 {Object.values(Category).map(c => <option key={c} value={c}>{t.categories[c]}</option>)}
               </select>

               <select 
                className="p-2 rounded-lg bg-gray-50 dark:bg-gray-800 text-sm border dark:border-gray-700"
                value={filters.status}
                onChange={(e) => setFilters({...filters, status: e.target.value as Status | 'All'})}
               >
                 <option value="All">{t.filters.all} {t.labels.status}</option>
                 {Object.values(Status).map(s => <option key={s} value={s}>{t.statuses[s]}</option>)}
               </select>

               <select 
                className="p-2 rounded-lg bg-gray-50 dark:bg-gray-800 text-sm border dark:border-gray-700"
                value={sortField}
                onChange={(e) => setSortField(e.target.value as SortField)}
               >
                 <option value="createdAt">{t.filters.newest}</option>
                 <option value="price">{t.filters.priceHigh}</option>
                 <option value="priority">{t.filters.sortBy} {t.labels.priority}</option>
               </select>

               <div className="col-span-2 grid grid-cols-2 gap-2 mt-1">
                 <Button size="sm" variant="ghost" onClick={handleExport} className="justify-center border dark:border-gray-700">
                    <Download size={14} className="mr-2" /> {t.export}
                 </Button>
                 <Button size="sm" variant="ghost" onClick={handleImportClick} className="justify-center border dark:border-gray-700">
                    <Upload size={14} className="mr-2" /> {t.import}
                 </Button>
               </div>
            </div>
          </div>
        </div>
      </header>

      {/* --- Stats Bar --- */}
      <div className="max-w-3xl mx-auto px-4 py-2">
        <div className="flex justify-between items-center text-sm text-gray-500 dark:text-gray-400">
           <span>{stats.count} {t.count}</span>
           <span>{t.total}: <span className="font-semibold text-gray-900 dark:text-gray-100">{stats.total.toLocaleString(lang === 'en' ? 'en-US' : 'te-IN', { style: 'currency', currency: 'INR' })}</span></span>
        </div>
      </div>

      {/* --- Main List --- */}
      <main className="max-w-3xl mx-auto px-4 py-2 space-y-4">
        {filteredItems.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-center opacity-60">
             <div className="w-20 h-20 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                <Filter size={32} className="text-gray-400" />
             </div>
             <p className="text-lg font-medium">{t.emptyState}</p>
          </div>
        ) : (
          filteredItems.map(item => (
            <ItemCard 
              key={item.id} 
              item={item} 
              onEdit={(i) => { setEditingItem(i); setIsFormOpen(true); }}
              onDelete={initiateDelete}
              lang={lang}
            />
          ))
        )}
      </main>

      {/* --- Floating Action Button --- */}
      <div className="fixed bottom-6 right-6 z-40">
        <button
          onClick={() => { setEditingItem(null); setIsFormOpen(true); }}
          className="bg-blue-600 hover:bg-blue-700 text-white w-14 h-14 rounded-full shadow-lg shadow-blue-600/30 flex items-center justify-center transition-transform hover:scale-105 active:scale-95 focus:outline-none focus:ring-4 focus:ring-blue-300 dark:focus:ring-blue-900"
          aria-label={t.addItem}
        >
          <Plus size={28} />
        </button>
      </div>

      {/* --- Modal --- */}
      <ItemForm 
        isOpen={isFormOpen} 
        onClose={() => setIsFormOpen(false)} 
        onSave={handleSaveItem}
        initialData={editingItem}
        lang={lang}
      />

      <ConfirmDialog 
        isOpen={!!itemToDelete}
        onClose={() => setItemToDelete(null)}
        onConfirm={confirmDelete}
        title={t.labels.deleteTitle}
        message={t.labels.confirmDelete}
        confirmLabel={t.labels.delete}
        cancelLabel={t.labels.cancel}
      />

    </div>
  );
};

export default App;

import React from 'react';
import { Button } from './ui/Button';
import { AlertTriangle } from 'lucide-react';

interface ConfirmDialogProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  title: string;
  message: string;
  confirmLabel: string;
  cancelLabel: string;
}

export const ConfirmDialog: React.FC<ConfirmDialogProps> = ({
  isOpen,
  onClose,
  onConfirm,
  title,
  message,
  confirmLabel,
  cancelLabel
}) => {
  if (!isOpen) return null;

  return (
    <div 
      className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200"
      onClick={onClose}
    >
      <div 
        className="bg-white dark:bg-gray-900 rounded-xl shadow-xl w-full max-w-sm p-6 transform transition-all animate-in zoom-in-95 duration-200"
        role="dialog"
        aria-modal="true"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex flex-col items-center text-center">
          <div className="w-12 h-12 rounded-full bg-red-100 dark:bg-red-900/30 flex items-center justify-center mb-4 text-red-600 dark:text-red-400">
            <AlertTriangle size={24} />
          </div>

          <h3 className="text-lg font-bold text-gray-900 dark:text-gray-100 mb-2">
            {title}
          </h3>

          <p className="text-sm text-gray-500 dark:text-gray-400 mb-6">
            {message}
          </p>

          <div className="flex gap-3 w-full">
            <Button variant="secondary" onClick={onClose} fullWidth>
              {cancelLabel}
            </Button>
            <Button variant="danger" onClick={onConfirm} fullWidth>
              {confirmLabel}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

