                  <button 
                    onClick={() => { 
                      onDelete(item.id); 
                      setShowMenu(false); 
                    }}
                    className="w-full px-4 py-2 text-left text-sm flex items-center gap-2 text-red-600 hover:bg-red-50/50 dark:hover:bg-red-900/20 transition-colors"
                  >
                    <Trash2 size={14} /> {t.labels.delete}
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      <div className="flex flex-wrap items-center gap-2 mb-3">
        <span className={`px-2.5 py-1 rounded-lg text-xs font-semibold border ${priorityColors[item.priority]}`}>
          {t.priorities[item.priority]}
        </span>
        <span className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-medium bg-black/5 dark:bg-white/5 text-gray-600 dark:text-gray-400">
          <Calendar size={12} /> {formattedDate}
        </span>
        {item.platform && (
          <span className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-medium bg-indigo-500/10 text-indigo-700 dark:text-indigo-300">
            <ShoppingBag size={12} /> {item.platform}
