import { ItemCard } from './components/ItemCard';
import { ConfirmDialog } from './components/ConfirmDialog';
import { Button } from './components/ui/Button';
import { 
  Plus, 
  Search, 
  Filter, 
  Download, 
  Upload,
  Languages, 
  Moon, 
  Sun,
  LayoutGrid,
  ListFilter
} from 'lucide-react';

const App: React.FC = () => {
  // --- State Management ---
