  useEffect(() => {
    const savedItems = localStorage.getItem(STORAGE_KEY);
    const savedTheme = localStorage.getItem(THEME_KEY) as Theme;
    const savedLang = localStorage.getItem(LANG_KEY) as Language;

    if (savedItems) setItems(JSON.parse(savedItems));
    if (savedTheme) setTheme(savedTheme);
    if (savedLang) setLang(savedLang);
    else {
      // Auto-detect browser language if not saved
      if (navigator.language.startsWith('te')) setLang('te');
    }
  }, []);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, theme);
    document.documentElement.className = theme;
  }, [theme]);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  // --- Handlers ---

  const handleSaveItem = (itemData: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => {
    const now = Date.now();
    if (editingItem) {
      setItems(prev => prev.map(item => 
        item.id === editingItem.id 
          ? { ...item, ...itemData, updatedAt: now } 
          : item
      ));
    } else {
      const newItem: WishlistItem = {
        ...itemData,
        id: crypto.randomUUID(),
        createdAt: now,
        updatedAt: now
      };
      setItems(prev => [newItem, ...prev]);
    }
    setEditingItem(null);
  };

  const initiateDelete = (id: string) => {
    setItemToDelete(id);
  };

  const confirmDelete = () => {
    if (itemToDelete) {
      setItems(prev => prev.filter(item => item.id !== itemToDelete));
      setItemToDelete(null);
    }
  };

  const handleExport = () => {
    const headers = ['Name', 'Category', 'Price', 'Priority', 'Status', 'Platform', 'Notes', 'Link', 'Created Date'];
    const csvContent = [
      headers.join(','),
      ...items.map(item => [
        `"${item.name.replace(/"/g, '""')}"`,
        item.category,
        item.price,
        item.priority,
        item.status,
        item.platform || EcommercePlatform.Other,
        `"${(item.notes || '').replace(/"/g, '""')}"`,
        `"${(item.link || '').replace(/"/g, '""')}"`,
        new Date(item.createdAt).toISOString().split('T')[0]
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `wishlog_export_${new Date().toISOString().slice(0,10)}.csv`;
    link.click();
  };

  const handleImportClick = () => {
    if (fileInputRef.current) {
