                </div>
             </div>
             <p className="text-lg font-medium text-gray-600 dark:text-gray-300 max-w-xs mx-auto leading-relaxed animate-in fade-in slide-in-from-bottom-4 duration-700">
               {t.emptyState}
             </p>
          </div>
        ) : (
          filteredItems.map(item => (
            <ItemCard 
              key={item.id} 
              item={item} 
              onEdit={(i) => { setEditingItem(i); setIsFormOpen(true); }}
              onDelete={initiateDelete}
              lang={lang}
            />
          ))
        )}
      </main>

      {/* --- Floating Action Button --- */}
      <div className="fixed bottom-8 right-8 z-40">
        <button
          onClick={() => { setEditingItem(null); setIsFormOpen(true); }}
          className="group relative w-16 h-16 flex items-center justify-center bg-gradient-to-br from-blue-600 to-indigo-600 text-white rounded-2xl shadow-lg shadow-blue-500/40 hover:shadow-blue-500/60 hover:scale-105 active:scale-95 transition-all duration-300"
          aria-label={t.addItem}
        >
          <div className="absolute inset-0 bg-white/20 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity" />
          <Plus size={32} className="relative z-10" />
        </button>
      </div>

      {/* --- Modal --- */}
      <ItemForm 
        isOpen={isFormOpen} 
        onClose={() => setIsFormOpen(false)} 
        onSave={handleSaveItem}
        initialData={editingItem}
        lang={lang}
      />

      <ConfirmDialog 
        isOpen={!!itemToDelete}
        onClose={() => setItemToDelete(null)}
        onConfirm={confirmDelete}
        title={t.labels.deleteTitle}
        message={t.labels.confirmDelete}
        confirmLabel={t.labels.delete}
        cancelLabel={t.labels.cancel}
      />

    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  WishlistItem, 
  Category, 
  Priority, 
  Status, 
  EcommercePlatform, 
  FilterState, 
  SortField, 
  Language, 
  Theme 
} from './types';
import { TRANSLATIONS, STORAGE_KEY, THEME_KEY, LANG_KEY } from './constants';
import { ItemForm } from './components/ItemForm';
import { ItemCard } from './components/ItemCard';
import { ConfirmDialog } from './components/ConfirmDialog';
import { Button } from './components/ui/Button';
import { 
  Plus, 
  Search, 
  Filter, 
  Download, 
  Upload,
  Languages, 
  Moon, 
  Sun,
  LayoutGrid,
  ListFilter
} from 'lucide-react';

const App: React.FC = () => {
  // --- State Management ---
  const [items, setItems] = useState<WishlistItem[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<WishlistItem | null>(null);
  const [itemToDelete, setItemToDelete] = useState<string | null>(null);

  // Settings
  const [lang, setLang] = useState<Language>('en');
  const [theme, setTheme] = useState<Theme>('light');

  // Filters & Search
  const [search, setSearch] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
    category: 'All',
    priority: 'All',
    status: 'All'
  });
  const [sortField, setSortField] = useState<SortField>('createdAt');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const t = TRANSLATIONS[lang];

  // --- Effects ---

  // Load initial data
  useEffect(() => {
    const savedItems = localStorage.getItem(STORAGE_KEY);
    const savedTheme = localStorage.getItem(THEME_KEY) as Theme;
    const savedLang = localStorage.getItem(LANG_KEY) as Language;

    if (savedItems) setItems(JSON.parse(savedItems));
    if (savedTheme) setTheme(savedTheme);
    if (savedLang) setLang(savedLang);
    else {
      // Auto-detect browser language if not saved
      if (navigator.language.startsWith('te')) setLang('te');
    }
  }, []);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, theme);
    document.documentElement.className = theme;
  }, [theme]);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  // --- Handlers ---

  const handleSaveItem = (itemData: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => {
    const now = Date.now();
    if (editingItem) {
      setItems(prev => prev.map(item => 
        item.id === editingItem.id 
          ? { ...item, ...itemData, updatedAt: now } 
          : item
      ));
    } else {
      const newItem: WishlistItem = {
        ...itemData,
        id: crypto.randomUUID(),
        createdAt: now,
        updatedAt: now
      };
      setItems(prev => [newItem, ...prev]);
    }
    setEditingItem(null);
  };

  const initiateDelete = (id: string) => {
    setItemToDelete(id);
  };

  const confirmDelete = () => {
    if (itemToDelete) {
      setItems(prev => prev.filter(item => item.id !== itemToDelete));
      setItemToDelete(null);
    }
  };

  const handleExport = () => {
    const headers = ['Name', 'Category', 'Price', 'Priority', 'Status', 'Platform', 'Notes', 'Link', 'Created Date'];
    const csvContent = [
      headers.join(','),
      ...items.map(item => [
        `"${item.name.replace(/"/g, '""')}"`,
        item.category,
        item.price,
        item.priority,
        item.status,
        item.platform || EcommercePlatform.Other,
        `"${(item.notes || '').replace(/"/g, '""')}"`,
        `"${(item.link || '').replace(/"/g, '""')}"`,
        new Date(item.createdAt).toISOString().split('T')[0]
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `wishlog_export_${new Date().toISOString().slice(0,10)}.csv`;
    link.click();
  };

  const handleImportClick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const parseCSVLine = (text: string) => {
    const result = [];
    let curr = '';
    let inQuote = false;
    for (let i = 0; i < text.length; i++) {
        const char = text[i];
        if (char === '"') {
            if (inQuote && text[i+1] === '"') {
                curr += '"';
                i++;
            } else {
                inQuote = !inQuote;
            }
        } else if (char === ',' && !inQuote) {
            result.push(curr);
            curr = '';
        } else {
            curr += char;
        }
    }
    result.push(curr);
    return result;
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const lines = content.split(/\r?\n/).filter(line => line.trim() !== '');

        // Skip header row
        const dataLines = lines.slice(1);

        const newItems: WishlistItem[] = [];
        const now = Date.now();

        dataLines.forEach((line, index) => {
          const cols = parseCSVLine(line);

          // Relaxed check: Ensure minimum required fields exist (Name, Category, Price, Priority, Status)
          if (cols.length < 5) {
            console.warn(`Skipping line ${index + 2}: Insufficient columns`, cols);
            return;
          }

          let name, categoryStr, priceStr, priorityStr, statusStr;
          let platformStr = '', notes = '', link = '', dateStr = '';

          // Assign based on column count to handle versioning and Excel artifacts
          // Trim all columns first
          const trimmedCols = cols.map(c => c.trim());

          if (trimmedCols.length >= 9) {
              // V3: Name, Category, Price, Priority, Status, Platform, Notes, Link, Created Date
              // Taking the first 9 columns explicitly to ignore trailing empty cols
              [name, categoryStr, priceStr, priorityStr, statusStr, platformStr, notes, link, dateStr] = trimmedCols;
          } else if (trimmedCols.length === 8) {
              // V2: Name, Category, Price, Priority, Status, Notes, Link, Created Date
              [name, categoryStr, priceStr, priorityStr, statusStr, notes, link, dateStr] = trimmedCols;
              platformStr = EcommercePlatform.Other;
          } else {
              // V1 or Minimal: Name, Category, Price, Priority, Status, Notes, Date
              [name, categoryStr, priceStr, priorityStr, statusStr] = trimmedCols;
              if (trimmedCols.length > 5) notes = trimmedCols[5];
              if (trimmedCols.length > 6) dateStr = trimmedCols[6]; // In V1, date was last

              platformStr = EcommercePlatform.Other;
              link = '';
          }

          // Validate and Parse
          const category = Object.values(Category).includes(categoryStr as Category) ? categoryStr as Category : Category.Others;
          const priority = Object.values(Priority).includes(priorityStr as Priority) ? priorityStr as Priority : Priority.Medium;
          const status = Object.values(Status).includes(statusStr as Status) ? statusStr as Status : Status.Planned;
          const platform = Object.values(EcommercePlatform).includes(platformStr as EcommercePlatform) ? platformStr as EcommercePlatform : EcommercePlatform.Other;

          // Clean price (remove currency symbols, commas, etc.)
          const cleanPriceStr = priceStr ? priceStr.replace(/[^0-9.]/g, '') : '0';
          const price = parseFloat(cleanPriceStr) || 0;

          const newItem: WishlistItem = {
            id: crypto.randomUUID(),
            name: name || 'Untitled',
            category,
            price,
            priority,
            status,
            platform,
            notes: notes || '',
            link: link || '',
            createdAt: dateStr && !isNaN(Date.parse(dateStr)) ? new Date(dateStr).getTime() : now,
            updatedAt: now
          };
          newItems.push(newItem);
        });

        if (newItems.length > 0) {
          setItems(prev => [...prev, ...newItems]);
          alert(t.importSuccess.replace('{count}', newItems.length.toString()));
          setShowFilters(false); // Close filters on success
        } else {
          console.warn("No valid items parsed.");
          alert(t.importError);
        }
      } catch (err) {
        console.error("Import failed:", err);
        alert(t.importError);
      }
    };
    reader.readAsText(file);
  };

  const toggleLanguage = () => setLang(prev => prev === 'en' ? 'te' : 'en');
  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  // --- Derived State ---

  const filteredItems = useMemo(() => {
    return items
      .filter(item => {
        const matchesSearch = item.name.toLowerCase().includes(search.toLowerCase());
        const matchesCategory = filters.category === 'All' || item.category === filters.category;
        const matchesPriority = filters.priority === 'All' || item.priority === filters.priority;
        const matchesStatus = filters.status === 'All' || item.status === filters.status;
        return matchesSearch && matchesCategory && matchesPriority && matchesStatus;
      })
      .sort((a, b) => {
        if (sortField === 'price') return b.price - a.price; // Descending price
        if (sortField === 'priority') {
          const pMap = { [Priority.High]: 3, [Priority.Medium]: 2, [Priority.Low]: 1 };
          return pMap[b.priority] - pMap[a.priority];
        }
        return b.createdAt - a.createdAt; // Newest first default
      });
  }, [items, search, filters, sortField]);

  const stats = useMemo(() => {
    const total = filteredItems.reduce((acc, curr) => acc + curr.price, 0);
    return { count: filteredItems.length, total };
  }, [filteredItems]);

  return (
    <div className="min-h-screen relative overflow-x-hidden text-gray-800 dark:text-gray-100 transition-colors duration-500">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload}
        onClick={(e) => { (e.target as HTMLInputElement).value = ''; }}
        accept=".csv,text/csv,application/vnd.ms-excel,text/plain"
        className="hidden" 
      />

      {/* --- Liquid Background --- */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none z-0">
         <div className="absolute top-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-purple-400/20 dark:bg-purple-900/20 rounded-full blur-[80px] animate-blob mix-blend-multiply dark:mix-blend-screen"></div>
         <div className="absolute top-[20%] right-[-10%] w-[50vw] h-[50vw] bg-blue-400/20 dark:bg-blue-900/20 rounded-full blur-[80px] animate-blob animation-delay-2000 mix-blend-multiply dark:mix-blend-screen"></div>
         <div className="absolute bottom-[-20%] left-[20%] w-[60vw] h-[60vw] bg-indigo-400/20 dark:bg-indigo-900/20 rounded-full blur-[80px] animate-blob animation-delay-4000 mix-blend-multiply dark:mix-blend-screen"></div>
      </div>

      {/* --- Header --- */}
      <header className="sticky top-0 z-30 bg-white/60 dark:bg-gray-900/60 backdrop-blur-xl border-b border-white/20 dark:border-white/5 shadow-sm">
        <div className="max-w-3xl mx-auto px-4 py-3">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl text-white shadow-lg shadow-blue-500/30">
                <LayoutGrid size={20} />
              </div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
                {t.appTitle}
              </h1>
            </div>
            <div className="flex gap-2">
              <button onClick={toggleLanguage} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors" title="Switch Language">
                <Languages size={20} />
                <span className="sr-only">Language</span>
              </button>
              <button onClick={toggleTheme} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors" title="Toggle Theme">
                {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
                <span className="sr-only">Theme</span>
              </button>
            </div>
          </div>

          <div className="flex gap-2">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input
                type="text"
                placeholder={t.searchPlaceholder}
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-10 pr-4 py-2 rounded-xl bg-gray-100/50 dark:bg-black/20 border border-transparent focus:bg-white dark:focus:bg-black/40 focus:border-blue-500/50 focus:ring-4 focus:ring-blue-500/10 outline-none text-sm transition-all"
              />
            </div>
            <button 
              onClick={() => setShowFilters(!showFilters)}
              className={`p-2 rounded-xl border transition-all duration-300 ${showFilters ? 'bg-blue-500 text-white border-blue-500 shadow-lg shadow-blue-500/30' : 'bg-white/50 dark:bg-black/20 border-white/20 dark:border-white/10 hover:bg-white dark:hover:bg-gray-800'}`}
            >
              <ListFilter size={20} />
            </button>
          </div>

          {/* Collapsible Filters */}
          <div className={`overflow-hidden transition-all duration-300 ease-in-out ${showFilters ? 'max-h-80 opacity-100 mt-3' : 'max-h-0 opacity-0'}`}>
            <div className="glass-panel rounded-xl p-3 grid grid-cols-2 gap-2">
               <select 
                className="p-2 rounded-lg bg-white/50 dark:bg-black/20 text-sm border border-white/20 dark:border-white/10 focus:ring-2 focus:ring-blue-500/30 outline-none"
                value={filters.category}
                onChange={(e) => setFilters({...filters, category: e.target.value as Category | 'All'})}
               >
                 <option value="All">{t.filters.all} {t.labels.category}</option>
                 {Object.values(Category).map(c => <option key={c} value={c}>{t.categories[c]}</option>)}
               </select>

               <select 
                className="p-2 rounded-lg bg-white/50 dark:bg-black/20 text-sm border border-white/20 dark:border-white/10 focus:ring-2 focus:ring-blue-500/30 outline-none"
                value={filters.status}
                onChange={(e) => setFilters({...filters, status: e.target.value as Status | 'All'})}
               >
                 <option value="All">{t.filters.all} {t.labels.status}</option>
                 {Object.values(Status).map(s => <option key={s} value={s}>{t.statuses[s]}</option>)}
               </select>

               <select 
                className="p-2 rounded-lg bg-white/50 dark:bg-black/20 text-sm border border-white/20 dark:border-white/10 focus:ring-2 focus:ring-blue-500/30 outline-none"
                value={sortField}
                onChange={(e) => setSortField(e.target.value as SortField)}
               >
                 <option value="createdAt">{t.filters.newest}</option>
                 <option value="price">{t.filters.priceHigh}</option>
                 <option value="priority">{t.filters.sortBy} {t.labels.priority}</option>
               </select>

               <div className="col-span-2 grid grid-cols-2 gap-2 mt-1">
                 <Button size="sm" variant="ghost" onClick={handleExport} className="justify-center border border-white/20 dark:border-white/10 bg-white/30 dark:bg-white/5">
                    <Download size={14} className="mr-2" /> {t.export}
                 </Button>
                 <Button size="sm" variant="ghost" onClick={handleImportClick} className="justify-center border border-white/20 dark:border-white/10 bg-white/30 dark:bg-white/5">
                    <Upload size={14} className="mr-2" /> {t.import}
                 </Button>
               </div>
            </div>
          </div>
        </div>
      </header>

      {/* --- Stats Bar --- */}
      <div className="max-w-3xl mx-auto px-4 py-3 relative z-10">
        <div className="flex justify-between items-center text-sm px-4 py-2 rounded-full glass-panel shadow-sm">
           <span className="text-gray-600 dark:text-gray-300 font-medium">{stats.count} {t.count}</span>
           <span className="text-gray-600 dark:text-gray-300 font-medium">{t.total}: <span className="text-blue-600 dark:text-blue-400 font-bold">{stats.total.toLocaleString(lang === 'en' ? 'en-US' : 'te-IN', { style: 'currency', currency: 'INR' })}</span></span>
        </div>
      </div>

      {/* --- Main List --- */}
      <main className="max-w-3xl mx-auto px-4 py-2 space-y-4 relative z-10 min-h-[50vh]">
        {filteredItems.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-24 text-center">
             <div className="relative w-28 h-28 flex items-center justify-center mb-8">
                {/* Ambient glow */}
                <div className="absolute inset-0 bg-blue-500/20 dark:bg-blue-500/10 rounded-full blur-xl animate-pulse-slow" />

                {/* Ripple effect */}
                <div className="absolute inset-0 bg-blue-400/10 dark:bg-blue-400/5 rounded-full animate-[ping_3s_cubic-bezier(0,0,0.2,1)_infinite]" />

                {/* Glass container */}
                <div className="relative z-10 w-20 h-20 bg-gradient-to-br from-white/80 to-white/40 dark:from-gray-800/80 dark:to-gray-800/40 backdrop-blur-md rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/10 border border-white/50 dark:border-white/10">
                    <Filter size={32} className="text-blue-600 dark:text-blue-400 opacity-90" />
                </div>
             </div>
             <p className="text-lg font-medium text-gray-600 dark:text-gray-300 max-w-xs mx-auto leading-relaxed animate-in fade-in slide-in-from-bottom-4 duration-700">
               {t.emptyState}
             </p>
          </div>
        ) : (
          filteredItems.map(item => (
            <ItemCard 
              key={item.id} 
              item={item} 
              onEdit={(i) => { setEditingItem(i); setIsFormOpen(true); }}
              onDelete={initiateDelete}
              lang={lang}
            />
          ))
        )}
      </main>

      {/* --- Floating Action Button --- */}
      <div className="fixed bottom-8 right-8 z-40">
        <button
          onClick={() => { setEditingItem(null); setIsFormOpen(true); }}
          className="group relative w-16 h-16 flex items-center justify-center bg-gradient-to-br from-blue-600 to-indigo-600 text-white rounded-2xl shadow-lg shadow-blue-500/40 hover:shadow-blue-500/60 hover:scale-105 active:scale-95 transition-all duration-300"
          aria-label={t.addItem}
        >
          <div className="absolute inset-0 bg-white/20 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity" />
          <Plus size={32} className="relative z-10" />
        </button>
      </div>

      {/* --- Modal --- */}
      <ItemForm 
        isOpen={isFormOpen} 
        onClose={() => setIsFormOpen(false)} 
        onSave={handleSaveItem}
        initialData={editingItem}
        lang={lang}
      />

      <ConfirmDialog 
        isOpen={!!itemToDelete}
        onClose={() => setItemToDelete(null)}
        onConfirm={confirmDelete}
        title={t.labels.deleteTitle}
        message={t.labels.confirmDelete}
        confirmLabel={t.labels.delete}
        cancelLabel={t.labels.cancel}
      />

    </div>
  );
};

