           <span className="inline-block px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider bg-black/5 dark:bg-white/10 text-gray-500 dark:text-gray-400 mb-1">
             {t.categories[item.category]}
           </span>
           <h3 className="text-xl font-bold text-gray-900 dark:text-gray-50 break-words leading-tight">
             {item.name}
           </h3>
        </div>

        <div className="absolute right-4 top-4 flex items-center gap-2">
          <button 
            onClick={() => onEdit(item)} 
            className="p-2 rounded-xl text-blue-600 bg-blue-500/10 hover:bg-blue-500/20 dark:text-blue-300 transition-all border border-blue-200/50 dark:border-blue-800/30"
            aria-label={t.labels.editItem}
          >
            <Edit2 size={16} />
          </button>

          <div className="relative">
            <button 
              onClick={() => setShowMenu(!showMenu)} 
              className="p-2 rounded-xl text-gray-500 hover:bg-black/5 dark:hover:bg-white/10 transition-all"
