                <div className="absolute right-0 mt-2 w-32 glass-panel bg-white/90 dark:bg-gray-800/90 rounded-xl shadow-xl z-20 py-1 overflow-hidden animate-in zoom-in-95 duration-200 origin-top-right">
                  <button 
                    onClick={() => { 
                      onDelete(item.id); 
                      setShowMenu(false); 
                    }}
                    className="w-full px-4 py-2 text-left text-sm flex items-center gap-2 text-red-600 hover:bg-red-50/50 dark:hover:bg-red-900/20 transition-colors"
                  >
                    <Trash2 size={14} /> {t.labels.delete}
