                </div>
              </>
            )}
          </div>
        </div>
      </div>

      <div className="flex flex-wrap items-center gap-2 mb-3">
        <span className={`px-2.5 py-1 rounded-lg text-xs font-semibold border ${priorityColors[item.priority]}`}>
          {t.priorities[item.priority]}
        </span>
        <span className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-medium bg-black/5 dark:bg-white/5 text-gray-600 dark:text-gray-400">
          <Calendar size={12} /> {formattedDate}
        </span>
        {item.platform && (
          <span className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-medium bg-indigo-500/10 text-indigo-700 dark:text-indigo-300">
            <ShoppingBag size={12} /> {item.platform}
          </span>
        )}
      </div>

      {item.notes && (
        <div className="mb-4 text-sm text-gray-600 dark:text-gray-300 bg-white/40 dark:bg-black/20 p-3 rounded-xl border border-white/20 dark:border-white/5">
          {item.notes}
        </div>
      )}

      <div className="pt-3 border-t border-black/5 dark:border-white/10 flex justify-between items-center">
         <div className="flex items-center gap-3">
            <span className={`text-xs font-bold px-2 py-0.5 rounded bg-gray-100/50 dark:bg-gray-800/50 text-gray-500 dark:text-gray-400 uppercase tracking-wide`}>
              {t.statuses[item.status]}
            </span>
            {isSafeLink && (
               <a 
                href={item.link} 
                target="_blank" 
                rel="noopener noreferrer"
                className="flex items-center gap-1 text-xs font-bold text-blue-600 dark:text-blue-400 hover:underline px-2 py-1 rounded-lg hover:bg-blue-50/50 dark:hover:bg-blue-900/20 transition-colors"
               >
                 <ExternalLink size={12} /> {t.labels.visitLink}
               </a>
            )}
         </div>
         <span className="text-xl font-bold font-mono tracking-tight text-gray-900 dark:text-white">
            {formattedPrice}
         </span>
      </div>

    </div>
  );
