import React, { useMemo } from 'react';
import { WishlistItem, Category, Status } from '../types';
import { useSettings } from '../context/SettingsContext';
import { PieChart, BarChart2, TrendingUp } from 'lucide-react';

interface AnalyticsDashboardProps {
  items: WishlistItem[];
}

export const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({ items }) => {
  const { t, currency } = useSettings();

  const data = useMemo(() => {
    const byCategory: Record<string, number> = {};
    const byStatus: Record<string, number> = {
      [Status.Planned]: 0,
      [Status.Bought]: 0,
      [Status.Dropped]: 0
    };
    let totalPlanned = 0;
    let totalBought = 0;

    items.forEach(item => {
      // Sum price by category
      byCategory[item.category] = (byCategory[item.category] || 0) + item.price;

      // Count by status
      byStatus[item.status]++;

      if (item.status === Status.Planned) totalPlanned += item.price;
      if (item.status === Status.Bought) totalBought += item.price;
    });

    return { byCategory, byStatus, totalPlanned, totalBought };
  }, [items]);

  const maxCategoryValue = Math.max(...Object.values(data.byCategory), 1);
  const totalItems = items.length || 1;

  const formatPrice = (amount: number) => 
    amount.toLocaleString('en-US', { style: 'currency', currency });

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Summary Cards */}
      <div className="grid grid-cols-2 gap-4">
        <div className="glass-panel p-4 rounded-2xl border-l-4 border-l-blue-500">
          <h3 className="text-xs font-bold uppercase text-gray-500 dark:text-gray-400 mb-1">{t.statuses.Planned}</h3>
          <p className="text-xl font-bold text-gray-900 dark:text-white">{formatPrice(data.totalPlanned)}</p>
        </div>
        <div className="glass-panel p-4 rounded-2xl border-l-4 border-l-green-500">
          <h3 className="text-xs font-bold uppercase text-gray-500 dark:text-gray-400 mb-1">{t.statuses.Bought}</h3>
          <p className="text-xl font-bold text-gray-900 dark:text-white">{formatPrice(data.totalBought)}</p>
        </div>
      </div>

      {/* Spending by Category */}
      <div className="glass-panel p-5 rounded-2xl">
        <div className="flex items-center gap-2 mb-4">
          <BarChart2 size={20} className="text-blue-500" />
          <h3 className="font-bold text-gray-800 dark:text-gray-100">{t.analytics.spendingByCategory}</h3>
        </div>
        <div className="space-y-4">
          {Object.entries(data.byCategory)
            .sort(([, a], [, b]) => b - a)
            .map(([cat, amount]) => (
            <div key={cat}>
              <div className="flex justify-between text-sm mb-1">
                <span className="text-gray-600 dark:text-gray-300 font-medium">{t.categories[cat as Category]}</span>
                <span className="font-bold text-gray-900 dark:text-white">{formatPrice(amount)}</span>
              </div>
              <div className="h-2 w-full bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full"
                  style={{ width: `${(amount / maxCategoryValue) * 100}%` }}
                />
              </div>
            </div>
          ))}
          {Object.keys(data.byCategory).length === 0 && (
            <p className="text-sm text-gray-500 text-center py-4">{t.emptyState}</p>
          )}
        </div>
      </div>

      {/* Items by Status */}
      <div className="glass-panel p-5 rounded-2xl">
        <div className="flex items-center gap-2 mb-4">
          <PieChart size={20} className="text-indigo-500" />
          <h3 className="font-bold text-gray-800 dark:text-gray-100">{t.analytics.itemsByStatus}</h3>
        </div>
        <div className="space-y-3">
          {Object.entries(data.byStatus).map(([status, count]) => (
            <div key={status} className="flex items-center justify-between p-3 rounded-xl bg-white/40 dark:bg-white/5 border border-white/20 dark:border-white/5">
              <div className="flex items-center gap-3">
                <div className={`w-3 h-3 rounded-full ${
                  status === Status.Planned ? 'bg-blue-500' :
                  status === Status.Bought ? 'bg-green-500' : 'bg-gray-400'
                }`} />
                <span className="text-sm font-medium text-gray-700 dark:text-gray-200">{t.statuses[status as Status]}</span>
              </div>
              <div className="flex items-center gap-2">
                 <span className="text-sm font-bold">{count}</span>
                 <span className="text-xs text-gray-500">({Math.round((count / totalItems) * 100)}%)</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { WishlistItem, EcommercePlatform, Category, Priority, Status } from '../types';
import { STORAGE_KEY, VALIDATION_LIMITS } from '../constants';
import { useToast } from '../context/ToastContext';
import { useSettings } from '../context/SettingsContext';

export const useWishlist = () => {
  const [items, setItems] = useState<WishlistItem[]>([]);
  const [lastActionTime, setLastActionTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { showToast } = useToast();
  const { t } = useSettings();

  // Load data
  useEffect(() => {
    try {
      const savedItems = localStorage.getItem(STORAGE_KEY);
      if (savedItems) setItems(JSON.parse(savedItems));
    } catch (error) {
      console.error("Failed to load local storage data", error);
      showToast("Failed to load saved items", "error");
    }
  }, []);

  // Persist data
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  // Helpers
  const isRateLimited = () => {
    const now = Date.now();
    if (now - lastActionTime < VALIDATION_LIMITS.RATE_LIMIT_MS) {
      showToast(t.validation.rateLimit, "error");
      return true;
    }
    setLastActionTime(now);
    return false;
  };

  const sanitizeString = (str: string, maxLength: number): string => {
    if (!str) return '';
    return str.replace(/[<>]/g, '').slice(0, maxLength);
  };

  // Actions
  const saveItem = (itemData: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>, editingId?: string) => {
    const now = Date.now();

    const cleanData = {
      ...itemData,
      name: sanitizeString(itemData.name, VALIDATION_LIMITS.NAME_MAX_LENGTH),
      notes: sanitizeString(itemData.notes || '', VALIDATION_LIMITS.NOTES_MAX_LENGTH),
      platform: sanitizeString(itemData.platform || '', VALIDATION_LIMITS.PLATFORM_MAX_LENGTH),
      imageUrl: itemData.imageUrl ? sanitizeString(itemData.imageUrl, VALIDATION_LIMITS.URL_MAX_LENGTH) : undefined,
      price: Math.max(VALIDATION_LIMITS.PRICE_MIN, Math.min(itemData.price, VALIDATION_LIMITS.PRICE_MAX))
    };

    if (editingId) {
      setItems(prev => prev.map(item => 
        item.id === editingId 
          ? { ...item, ...cleanData, updatedAt: now } 
          : item
      ));
      showToast("Item updated successfully", "success");
    } else {
      const newItem: WishlistItem = {
        ...cleanData,
        id: crypto.randomUUID(),
        createdAt: now,
        updatedAt: now
      };
      setItems(prev => [newItem, ...prev]);
      showToast("Item added successfully", "success");
    }
  };

  const deleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
    showToast("Item deleted", "success");
  };

  const exportCSV = () => {
    if (isRateLimited()) return;

    const headers = ['Name', 'Category', 'Price', 'Priority', 'Status', 'Platform', 'Notes', 'Link', 'Created Date', 'Image URL'];
    const csvContent = [
      headers.join(','),
      ...items.map(item => [
        `"${item.name.replace(/"/g, '""')}"`,
        item.category,
        item.price,
        item.priority,
        item.status,
        item.platform || EcommercePlatform.Other,
        `"${(item.notes || '').replace(/"/g, '""')}"`,
        `"${(item.link || '').replace(/"/g, '""')}"`,
        new Date(item.createdAt).toISOString().split('T')[0],
        `"${(item.imageUrl || '').replace(/"/g, '""')}"`
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `wishlog_export_${new Date().toISOString().slice(0,10)}.csv`;
    link.click();
    showToast("Export started", "success");
  };

  const triggerImport = () => {
    if (isRateLimited()) return;
    if (fileInputRef.current) fileInputRef.current.click();
  };

  const parseCSVLine = (text: string) => {
    const result = [];
    let curr = '';
    let inQuote = false;
    for (let i = 0; i < text.length; i++) {
        const char = text[i];
        if (char === '"') {
            if (inQuote && text[i+1] === '"') {
                curr += '"';
                i++;
            } else {
                inQuote = !inQuote;
            }
        } else if (char === ',' && !inQuote) {
            result.push(curr);
            curr = '';
        } else {
            curr += char;
        }
    }
    result.push(curr);
    return result;
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (isRateLimited()) {
       if (event.target) event.target.value = '';
       return;
    }

    const file = event.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
        showToast("File too large (Max 5MB)", "error");
        return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const cleanContent = content.replace(/[\x00-\x09\x0B-\x1F\x7F]/g, "");
        const lines = cleanContent.split(/\r?\n/).filter(line => line.trim() !== '');
        const dataLines = lines.slice(1); // Skip header
        const newItems: WishlistItem[] = [];
        const now = Date.now();

        dataLines.forEach((line) => {
          const cols = parseCSVLine(line);
          if (cols.length < 5) return;

          let name, categoryStr, priceStr, priorityStr, statusStr;
          let platformStr = '', notes = '', link = '', dateStr = '', imageUrl = '';
          const trimmedCols = cols.map(c => c.trim());

          // Handle variable column lengths for backward compatibility
          if (trimmedCols.length >= 10) {
              [name, categoryStr, priceStr, priorityStr, statusStr, platformStr, notes, link, dateStr, imageUrl] = trimmedCols;
          } else if (trimmedCols.length === 9) {
              [name, categoryStr, priceStr, priorityStr, statusStr, platformStr, notes, link, dateStr] = trimmedCols;
          } else if (trimmedCols.length === 8) {
              [name, categoryStr, priceStr, priorityStr, statusStr, notes, link, dateStr] = trimmedCols;
              platformStr = EcommercePlatform.Other;
          } else {
              [name, categoryStr, priceStr, priorityStr, statusStr] = trimmedCols;
              if (trimmedCols.length > 5) notes = trimmedCols[5];
              if (trimmedCols.length > 6) dateStr = trimmedCols[6];
              platformStr = EcommercePlatform.Other;
              link = '';
          }

          const category = Object.values(Category).includes(categoryStr as Category) ? categoryStr as Category : Category.Others;
          const priority = Object.values(Priority).includes(priorityStr as Priority) ? priorityStr as Priority : Priority.Medium;
          const status = Object.values(Status).includes(statusStr as Status) ? statusStr as Status : Status.Planned;

          const cleanName = sanitizeString(name || 'Untitled', VALIDATION_LIMITS.NAME_MAX_LENGTH);
          const cleanPlatform = sanitizeString(platformStr || EcommercePlatform.Other, VALIDATION_LIMITS.PLATFORM_MAX_LENGTH);
          const cleanNotes = sanitizeString(notes || '', VALIDATION_LIMITS.NOTES_MAX_LENGTH);

          let cleanLink = '';
          if (link && (link.startsWith('http://') || link.startsWith('https://'))) {
              cleanLink = sanitizeString(link, VALIDATION_LIMITS.URL_MAX_LENGTH);
          }

          let cleanImageUrl = '';
          if (imageUrl && (imageUrl.startsWith('http://') || imageUrl.startsWith('https://'))) {
             cleanImageUrl = sanitizeString(imageUrl, VALIDATION_LIMITS.URL_MAX_LENGTH);
          }

          const cleanPriceStr = priceStr ? priceStr.replace(/[^0-9.]/g, '') : '0';
          let price = parseFloat(cleanPriceStr);
          if (isNaN(price) || price < 0) price = 0;
          if (price > VALIDATION_LIMITS.PRICE_MAX) price = VALIDATION_LIMITS.PRICE_MAX;

          const newItem: WishlistItem = {
            id: crypto.randomUUID(),
            name: cleanName,
            category,
            price,
            priority,
            status,
            platform: cleanPlatform,
            notes: cleanNotes,
            link: cleanLink,
            imageUrl: cleanImageUrl,
            createdAt: dateStr && !isNaN(Date.parse(dateStr)) ? new Date(dateStr).getTime() : now,
            updatedAt: now
          };
          newItems.push(newItem);
        });

        if (newItems.length > 0) {
          setItems(prev => [...prev, ...newItems]);
          showToast(t.importSuccess.replace('{count}', newItems.length.toString()), "success");
        } else {
          showToast(t.importError, "error");
        }
      } catch (err) {
        console.error("Import failed:", err);
        showToast(t.importError, "error");
      }
    };
    reader.readAsText(file);
  };

  return {
    items,
    fileInputRef,
    saveItem,
    deleteItem,
    exportCSV,
    triggerImport,
    handleFileUpload
  };
};

import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, EcommercePlatform } from '../types';
import { VALIDATION_LIMITS, ALLOWED_PROTOCOLS } from '../constants';
import { useSettings } from '../context/SettingsContext';
import { Button } from './ui/Button';
import { X, Link as LinkIcon, AlertCircle, Image as ImageIcon } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
}

interface ValidationErrors {
  name?: string;
  price?: string;
  platform?: string;
  link?: string;
  imageUrl?: string;
  notes?: string;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave }) => {
  const { t } = useSettings();

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [platformType, setPlatformType] = useState<EcommercePlatform>(EcommercePlatform.Amazon);
  const [customPlatform, setCustomPlatform] = useState('');
  const [notes, setNotes] = useState('');
  const [link, setLink] = useState('');
  const [imageUrl, setImageUrl] = useState('');

  const [errors, setErrors] = useState<ValidationErrors>({});

  const knownPlatforms = Object.values(EcommercePlatform) as string[];

  useEffect(() => {
    setErrors({});
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setNotes(initialData.notes || '');
      setLink(initialData.link || '');
      setImageUrl(initialData.imageUrl || '');

      const p = initialData.platform || EcommercePlatform.Other;
      if (knownPlatforms.includes(p) && p !== EcommercePlatform.Other) {
        setPlatformType(p as EcommercePlatform);
        setCustomPlatform('');
      } else {
        setPlatformType(EcommercePlatform.Other);
        setCustomPlatform(p === EcommercePlatform.Other ? '' : p);
      }

    } else {
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setPlatformType(EcommercePlatform.Amazon);
      setCustomPlatform('');
      setNotes('');
      setLink('');
      setImageUrl('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const validate = (): boolean => {
    const newErrors: ValidationErrors = {};
    let isValid = true;

    if (!name.trim()) {
      newErrors.name = t.validation.required;
      isValid = false;
    } else if (name.length > VALIDATION_LIMITS.NAME_MAX_LENGTH) {
      newErrors.name = t.validation.tooLong;
      isValid = false;
    }

    const numPrice = parseFloat(price);
    if (isNaN(numPrice) || numPrice < 0 || numPrice > VALIDATION_LIMITS.PRICE_MAX) {
      newErrors.price = t.validation.invalidPrice;
      isValid = false;
    }

    if (platformType === EcommercePlatform.Other && customPlatform.length > VALIDATION_LIMITS.PLATFORM_MAX_LENGTH) {
      newErrors.platform = t.validation.tooLong;
      isValid = false;
    }

    const validateUrl = (urlStr: string, field: 'link' | 'imageUrl') => {
        if (!urlStr.trim()) return;
        try {
            const url = new URL(urlStr);
            if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
                newErrors[field] = t.validation.invalidUrl;
                isValid = false;
            }
        } catch (e) {
            if (!urlStr.startsWith('http')) {
               // fixed later
            } else {
               newErrors[field] = t.validation.invalidUrl;
               isValid = false;
            }
        }
        if (urlStr.length > VALIDATION_LIMITS.URL_MAX_LENGTH) {
            newErrors[field] = t.validation.tooLong;
            isValid = false;
        }
    };

    validateUrl(link, 'link');
    validateUrl(imageUrl, 'imageUrl');

    if (notes.length > VALIDATION_LIMITS.NOTES_MAX_LENGTH) {
      newErrors.notes = t.validation.tooLong;
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    let finalPlatform = platformType as string;
    if (platformType === EcommercePlatform.Other) {
      finalPlatform = customPlatform.trim() || EcommercePlatform.Other;
    }

    const fixUrl = (u: string) => {
        let trimmed = u.trim();
        if (trimmed && !trimmed.startsWith('http://') && !trimmed.startsWith('https://')) {
            return `https://${trimmed}`;
        }
        return trimmed;
    };

    onSave({
      name: name.trim(),
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      platform: finalPlatform,
      notes: notes.trim(),
      link: fixUrl(link),
      imageUrl: fixUrl(imageUrl)
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/30 dark:bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="glass-panel w-full max-w-md max-h-[90vh] overflow-y-auto flex flex-col rounded-2xl shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-5 duration-300 border border-white/40 dark:border-white/10 bg-white/80 dark:bg-gray-900/80">

