            {item.imageUrl && (
                <span className="sm:hidden flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-medium bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300">
                    <ImageIcon size={12} /> Image
