import { useSettings } from './context/SettingsContext';
import { usePWA } from './hooks/usePWA';
import { ItemForm } from './components/ItemForm';
import { ItemCard } from './components/ItemCard';
import { AnalyticsDashboard } from './components/AnalyticsDashboard';
import { ConfirmDialog } from './components/ConfirmDialog';
import { Button } from './components/ui/Button';
import { 
  Plus, Search, Filter, Download, Upload,
  Languages, Moon, Sun, LayoutGrid, ListFilter, Settings, PieChart, List,
  WifiOff, Smartphone
} from 'lucide-react';

type ViewMode = 'list' | 'analytics';

const App: React.FC = () => {
  // Hooks & Context
  const { items, fileInputRef, saveItem, deleteItem, exportCSV, triggerImport, handleFileUpload } = useWishlist();
  const { theme, toggleTheme, toggleLanguage, t, currency, setCurrency, apiKey, setApiKey } = useSettings();
  const { isOffline, showInstallButton, installApp } = usePWA();

  // Local UI State
  const [view, setView] = useState<ViewMode>('list');
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<WishlistItem | null>(null);
  const [itemToDelete, setItemToDelete] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [fetchingItemIds, setFetchingItemIds] = useState<Set<string>>(new Set());
  const [filters, setFilters] = useState<FilterState>({
    category: 'All',
    priority: 'All',
    status: 'All'
  });
  const [sortField, setSortField] = useState<SortField>('createdAt');

  // Logic
  const filteredItems = useMemo(() => {
    return items
      .filter(item => {
        const matchesSearch = item.name.toLowerCase().includes(search.toLowerCase());
        const matchesCategory = filters.category === 'All' || item.category === filters.category;
        const matchesPriority = filters.priority === 'All' || item.priority === filters.priority;
        const matchesStatus = filters.status === 'All' || item.status === filters.status;
        return matchesSearch && matchesCategory && matchesPriority && matchesStatus;
      })
      .sort((a, b) => {
        if (sortField === 'price') return b.price - a.price;
        if (sortField === 'priority') {
          const pMap = { [Priority.High]: 3, [Priority.Medium]: 2, [Priority.Low]: 1 };
          return pMap[b.priority] - pMap[a.priority];
        }
        return b.createdAt - a.createdAt;
      });
  }, [items, search, filters, sortField]);

  const stats = useMemo(() => {
    const total = filteredItems.reduce((acc, curr) => acc + curr.price, 0);
    return { count: filteredItems.length, total };
  }, [filteredItems]);

  const handleEdit = (item: WishlistItem) => {
    setEditingItem(item);
    setIsFormOpen(true);
  };

  const handleFetchChange = (isFetching: boolean, itemId?: string) => {
    if (!itemId) return;
    setFetchingItemIds(prev => {
      const next = new Set(prev);
      if (isFetching) next.add(itemId);
      else next.delete(itemId);
      return next;
    });
