const App: React.FC = () => {
  // Hooks & Context
  const { items, fileInputRef, saveItem, deleteItem, exportCSV, triggerImport, handleFileUpload } = useWishlist();
  const { theme, toggleTheme, toggleLanguage, t, currency, setCurrency, serpApiKey, setSerpApiKey } = useSettings();
  const { isOffline, showInstallButton, installApp } = usePWA();

  // Local UI State
  const [view, setView] = useState<ViewMode>('list');
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<WishlistItem | null>(null);
  const [itemToDelete, setItemToDelete] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [fetchingItemIds, setFetchingItemIds] = useState<Set<string>>(new Set());
  const [filters, setFilters] = useState<FilterState>({
    category: 'All',
    priority: 'All',
    status: 'All'
  });
  const [sortField, setSortField] = useState<SortField>('createdAt');

  // Logic
  const filteredItems = useMemo(() => {
    return items
      .filter(item => {
        const matchesSearch = item.name.toLowerCase().includes(search.toLowerCase());
        const matchesCategory = filters.category === 'All' || item.category === filters.category;
        const matchesPriority = filters.priority === 'All' || item.priority === filters.priority;
        const matchesStatus = filters.status === 'All' || item.status === filters.status;
        return matchesSearch && matchesCategory && matchesPriority && matchesStatus;
      })
      .sort((a, b) => {
        if (sortField === 'price') return b.price - a.price;
        if (sortField === 'priority') {
          const pMap = { [Priority.High]: 3, [Priority.Medium]: 2, [Priority.Low]: 1 };
          return pMap[b.priority] - pMap[a.priority];
        }
        return b.createdAt - a.createdAt;
      });
  }, [items, search, filters, sortField]);

  const stats = useMemo(() => {
    const total = filteredItems.reduce((acc, curr) => acc + curr.price, 0);
    return { count: filteredItems.length, total };
  }, [filteredItems]);

  const handleEdit = (item: WishlistItem) => {
    setEditingItem(item);
    setIsFormOpen(true);
  };

  const handleFetchChange = (isFetching: boolean, itemId?: string) => {
    if (!itemId) return;
    setFetchingItemIds(prev => {
      const next = new Set(prev);
      if (isFetching) next.add(itemId);
      else next.delete(itemId);
      return next;
    });
  };

  const formattedTotal = stats.total.toLocaleString('en-US', { style: 'currency', currency: currency });

  return (
    <div className="min-h-screen relative overflow-x-hidden text-gray-800 dark:text-gray-100 transition-colors duration-500">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload}
        onClick={(e) => { (e.target as HTMLInputElement).value = ''; }}
        accept=".csv,text/csv,application/vnd.ms-excel,text/plain"
        className="hidden" 
      />

      {/* --- Liquid Background --- */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none z-0">
         <div className="absolute top-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-purple-400/20 dark:bg-purple-900/20 rounded-full blur-[80px] animate-blob mix-blend-multiply dark:mix-blend-screen"></div>
         <div className="absolute top-[20%] right-[-10%] w-[50vw] h-[50vw] bg-blue-400/20 dark:bg-blue-900/20 rounded-full blur-[80px] animate-blob animation-delay-2000 mix-blend-multiply dark:mix-blend-screen"></div>
         <div className="absolute bottom-[-20%] left-[20%] w-[60vw] h-[60vw] bg-indigo-400/20 dark:bg-indigo-900/20 rounded-full blur-[80px] animate-blob animation-delay-4000 mix-blend-multiply dark:mix-blend-screen"></div>
      </div>

      {/* --- Header --- */}
      <header className="sticky top-0 z-30 bg-white/60 dark:bg-gray-900/60 backdrop-blur-xl border-b border-white/20 dark:border-white/5 shadow-sm">

        {/* Offline Banner */}
        {isOffline && (
          <div className="bg-red-500 text-white text-xs font-bold text-center py-1 flex items-center justify-center gap-2 animate-in slide-in-from-top-0">
             <WifiOff size={12} />
             <span>Offline Mode - Changes saved locally</span>
          </div>
        )}

        <div className="max-w-3xl mx-auto px-3 py-3">
          <div className="flex items-center justify-between mb-3 gap-2">
            <div className="flex items-center gap-2 min-w-0">
              <div className="p-2 flex-shrink-0 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl text-white shadow-lg shadow-blue-500/30">
                <LayoutGrid size={20} />
              </div>
              <h1 className="text-lg sm:text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent truncate">
                {t.appTitle}
              </h1>
            </div>
            <div className="flex items-center gap-1 sm:gap-2 flex-shrink-0">
              {/* View Toggle */}
              <div className="flex bg-gray-200 dark:bg-gray-800 rounded-lg p-1 mr-1 sm:mr-2">
                <button 
                  onClick={() => setView('list')}
                  className={`p-1.5 rounded-md transition-all ${view === 'list' ? 'bg-white dark:bg-gray-600 shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
                >
                  <List size={18} />
                </button>
                <button 
                  onClick={() => setView('analytics')}
                  className={`p-1.5 rounded-md transition-all ${view === 'analytics' ? 'bg-white dark:bg-gray-600 shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
                >
                  <PieChart size={18} />
                </button>
              </div>

              <button onClick={() => setShowSettings(!showSettings)} className={`p-1.5 sm:p-2 rounded-full transition-colors ${showSettings ? 'bg-blue-500/20 text-blue-600' : 'hover:bg-black/5 dark:hover:bg-white/10'}`}>
                 <Settings size={20} />
              </button>
              <button onClick={toggleLanguage} className="p-1.5 sm:p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
                <Languages size={20} />
              </button>
              <button onClick={toggleTheme} className="p-1.5 sm:p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
                {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
              </button>
            </div>
          </div>

          {/* Settings Dropdown */}
          <div className={`overflow-hidden transition-all duration-300 ${showSettings ? 'max-h-[22rem] opacity-100 mb-3' : 'max-h-0 opacity-0'}`}>
             <div className="glass-panel p-4 rounded-xl space-y-4">
                <div className="flex items-center justify-between">
                    <span className="text-sm font-bold uppercase tracking-wider text-gray-500">{t.currency}</span>
                    <select 
                      value={currency} 
                      onChange={(e) => setCurrency(e.target.value as Currency)}
                      className="p-1.5 rounded-lg bg-white/50 dark:bg-black/20 border border-white/20 dark:border-white/10 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      <option value="INR">INR (₹)</option>
                      <option value="USD">USD ($)</option>
                      <option value="EUR">EUR (€)</option>
                      <option value="GBP">GBP (£)</option>
                    </select>
                </div>

                {/* SerpApi Input */}
                <div className="pt-2 border-t border-black/5 dark:border-white/10">
                    <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-1.5">
                        {t.serpApiLabel}
                    </label>
                    <input 
                        type="password"
                        value={serpApiKey}
                        onChange={(e) => setSerpApiKey(e.target.value)}
                        placeholder="Paste your key here..."
                        className="w-full p-2 rounded-lg bg-white/50 dark:bg-black/20 border border-white/20 dark:border-white/10 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                    />
                    <p className="text-[10px] text-gray-400 mt-1">
                        {t.serpApiDesc}
                    </p>
                </div>

                {showInstallButton && (
                  <Button onClick={installApp} variant="secondary" size="sm" fullWidth className="justify-center mt-2">
                    <Smartphone size={16} className="mr-2" /> Install App
                  </Button>
                )}
             </div>
          </div>

          {/* Search & Filter Bar - Only in List View */}
          {view === 'list' && (
            <>
              <div className="flex gap-2">
                <div className="relative flex-1 group">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-blue-500 transition-colors" size={18} />
                  <input
                    type="text"
                    placeholder={t.searchPlaceholder}
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 rounded-xl bg-gray-100/50 dark:bg-black/20 border border-transparent focus:bg-white dark:focus:bg-black/40 focus:border-blue-500/50 focus:ring-4 focus:ring-blue-500/10 outline-none text-sm transition-all"
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`p-2 rounded-xl border transition-all duration-300 ${showFilters ? 'bg-blue-500 text-white border-blue-500 shadow-lg shadow-blue-500/30' : 'bg-white/50 dark:bg-black/20 border-white/20 dark:border-white/10 hover:bg-white dark:hover:bg-gray-800'}`}
                >
                  <ListFilter size={20} />
                </button>
              </div>

              {/* Collapsible Filters */}
              <div className={`overflow-hidden transition-all duration-300 ease-in-out ${showFilters ? 'max-h-80 opacity-100 mt-3' : 'max-h-0 opacity-0'}`}>
                <div className="glass-panel rounded-xl p-3 grid grid-cols-2 gap-2">
                   <select 
                    className="p-2 rounded-lg bg-white/50 dark:bg-black/20 text-sm border border-white/20 dark:border-white/10 focus:ring-2 focus:ring-blue-500/30 outline-none"
                    value={filters.category}
                    onChange={(e) => setFilters({...filters, category: e.target.value as Category | 'All'})}
                   >
                     <option value="All">{t.filters.all} {t.labels.category}</option>
                     {Object.values(Category).map(c => <option key={c} value={c}>{t.categories[c]}</option>)}
                   </select>

                   <select 
                    className="p-2 rounded-lg bg-white/50 dark:bg-black/20 text-sm border border-white/20 dark:border-white/10 focus:ring-2 focus:ring-blue-500/30 outline-none"
                    value={filters.status}
                    onChange={(e) => setFilters({...filters, status: e.target.value as Status | 'All'})}
                   >
                     <option value="All">{t.filters.all} {t.labels.status}</option>
                     {Object.values(Status).map(s => <option key={s} value={s}>{t.statuses[s]}</option>)}
                   </select>

                   <select 
                    className="p-2 rounded-lg bg-white/50 dark:bg-black/20 text-sm border border-white/20 dark:border-white/10 focus:ring-2 focus:ring-blue-500/30 outline-none"
                    value={sortField}
                    onChange={(e) => setSortField(e.target.value as SortField)}
                   >
                     <option value="createdAt">{t.filters.newest}</option>
                     <option value="price">{t.filters.priceHigh}</option>
                     <option value="priority">{t.filters.sortBy} {t.labels.priority}</option>
                   </select>

                   <div className="col-span-2 grid grid-cols-2 gap-2 mt-1">
                     <Button size="sm" variant="ghost" onClick={exportCSV} className="justify-center border border-white/20 dark:border-white/10 bg-white/30 dark:bg-white/5">
                        <Download size={14} className="mr-2" /> {t.export}
                     </Button>
                     <Button size="sm" variant="ghost" onClick={triggerImport} className="justify-center border border-white/20 dark:border-white/10 bg-white/30 dark:bg-white/5">
                        <Upload size={14} className="mr-2" /> {t.import}
                     </Button>
                   </div>
                </div>
              </div>
            </>
          )}
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="max-w-3xl mx-auto px-4 py-4 space-y-4 relative z-10 min-h-[50vh]">

        {view === 'analytics' ? (
          <AnalyticsDashboard items={items} />
        ) : (
          <>
            {/* Stats Bar */}
            <div className="flex justify-between items-center text-sm px-4 py-2 rounded-full glass-panel shadow-sm">
               <span className="text-gray-600 dark:text-gray-300 font-medium">{stats.count} {t.count}</span>
               <span className="text-gray-600 dark:text-gray-300 font-medium">{t.total}: <span className="text-blue-600 dark:text-blue-400 font-bold">{formattedTotal}</span></span>
            </div>

            {filteredItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-24 text-center">
                 <div className="relative w-28 h-28 flex items-center justify-center mb-8">
                    <div className="absolute inset-0 bg-blue-500/20 dark:bg-blue-500/10 rounded-full blur-xl animate-pulse-slow" />
                    <div className="absolute inset-0 bg-blue-400/10 dark:bg-blue-400/5 rounded-full animate-[ping_3s_cubic-bezier(0,0,0.2,1)_infinite]" />
                    <div className="relative z-10 w-20 h-20 bg-gradient-to-br from-white/80 to-white/40 dark:from-gray-800/80 dark:to-gray-800/40 backdrop-blur-md rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/10 border border-white/50 dark:border-white/10">
                        <Filter size={32} className="text-blue-600 dark:text-blue-400 opacity-90" />
                    </div>
                 </div>
                 <p className="text-lg font-medium text-gray-600 dark:text-gray-300 max-w-xs mx-auto leading-relaxed animate-in fade-in slide-in-from-bottom-4 duration-700">
                   {t.emptyState}
                 </p>
                 {showInstallButton && (
                    <Button onClick={installApp} variant="secondary" size="sm" className="mt-6">
                      <Smartphone size={16} className="mr-2" /> Install App
                    </Button>
                 )}
              </div>
            ) : (
              filteredItems.map(item => (
                <ItemCard 
                  key={item.id} 
                  item={item} 
                  onEdit={handleEdit}
                  onDelete={setItemToDelete}
                  isLoading={fetchingItemIds.has(item.id)}
                />
              ))
            )}
          </>
        )}
      </main>

      {/* --- Floating Action Button --- */}
      <div className="fixed bottom-8 right-8 z-40">
        <button
          onClick={() => { setEditingItem(null); setIsFormOpen(true); }}
          className="group relative w-16 h-16 flex items-center justify-center bg-gradient-to-br from-blue-600 to-indigo-600 text-white rounded-2xl shadow-lg shadow-blue-500/40 hover:shadow-blue-500/60 hover:scale-105 active:scale-95 transition-all duration-300"
          aria-label={t.addItem}
        >
          <div className="absolute inset-0 bg-white/20 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity" />
          <Plus size={32} className="relative z-10" />
        </button>
      </div>

      {/* --- Modal --- */}
      <ItemForm 
        isOpen={isFormOpen} 
        onClose={() => setIsFormOpen(false)} 
        onSave={(data) => saveItem(data, editingItem?.id)}
        initialData={editingItem}
        onFetchChange={handleFetchChange}
      />

      <ConfirmDialog 
        isOpen={!!itemToDelete}
        onClose={() => setItemToDelete(null)}
        onConfirm={() => { if(itemToDelete) deleteItem(itemToDelete); setItemToDelete(null); }}
        title={t.labels.deleteTitle}
        message={t.labels.confirmDelete}
        confirmLabel={t.labels.delete}
        cancelLabel={t.labels.cancel}
      />

    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, EcommercePlatform } from '../types';
import { VALIDATION_LIMITS, ALLOWED_PROTOCOLS } from '../constants';
import { useSettings } from '../context/SettingsContext';
import { useToast } from '../context/ToastContext';
import { Button } from './ui/Button';
import { X, Paperclip, AlertCircle, Image as ImageIcon, Sparkles, Loader2, Zap } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onFetchChange?: (isFetching: boolean, itemId?: string) => void;
}

interface ValidationErrors {
  name?: string;
  price?: string;
  platform?: string;
  link?: string;
  imageUrl?: string;
  notes?: string;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave, onFetchChange }) => {
  const { t, serpApiKey } = useSettings();
  const { showToast } = useToast();

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [platformType, setPlatformType] = useState<EcommercePlatform>(EcommercePlatform.Amazon);
  const [customPlatform, setCustomPlatform] = useState('');
  const [notes, setNotes] = useState('');
  const [link, setLink] = useState('');
  const [imageUrl, setImageUrl] = useState('');

  const [isFetching, setIsFetching] = useState(false);
  const [fetchStatus, setFetchStatus] = useState<string>('');

  const [errors, setErrors] = useState<ValidationErrors>({});

  const knownPlatforms = Object.values(EcommercePlatform) as string[];

  useEffect(() => {
    setErrors({});
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setNotes(initialData.notes || '');
      setLink(initialData.link || '');
      setImageUrl(initialData.imageUrl || '');

      const p = initialData.platform || EcommercePlatform.Other;
      if (knownPlatforms.includes(p) && p !== EcommercePlatform.Other) {
        setPlatformType(p as EcommercePlatform);
        setCustomPlatform('');
      } else {
        setPlatformType(EcommercePlatform.Other);
        setCustomPlatform(p === EcommercePlatform.Other ? '' : p);
      }

    } else {
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setPlatformType(EcommercePlatform.Amazon);
      setCustomPlatform('');
      setNotes('');
      setLink('');
      setImageUrl('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const detectPlatformFromUrl = (url: string): string => {
    try {
      const hostname = new URL(url).hostname.replace('www.', '');
      if (hostname.includes('amazon')) return 'Amazon';
      if (hostname.includes('flipkart')) return 'Flipkart';
      if (hostname.includes('myntra')) return 'Myntra';
      if (hostname.includes('ajio')) return 'Ajio';
      return hostname.charAt(0).toUpperCase() + hostname.slice(1).split('.')[0];
    } catch {
      return '';
    }
  };

  const handleAutoFill = async () => {
    if (!link) return;

    // Simple URL validation
    try {
      new URL(link);
    } catch {
      setErrors({ ...errors, link: t.validation.invalidUrl });
      return;
    }

    setIsFetching(true);
    onFetchChange?.(true, initialData?.id);
    const platform = detectPlatformFromUrl(link);
    setFetchStatus(platform ? `Connecting to ${platform}...` : 'Fetching metadata...');

    try {
      // 1. Fetch Metadata with Microlink (Great for Title, Image, Platform)
      const encodedUrl = encodeURIComponent(link);
      const microlinkPromise = fetch(`https://api.microlink.io/?url=${encodedUrl}&palette=true&audio=false&video=false`);

      let serpPromise = null;
      if (serpApiKey) {
          // 2. Fetch Price with SerpApi (Google Search logic, if key provided)
          // We search for the exact URL to get the snippet which usually contains the price
          serpPromise = fetch(`https://serpapi.com/search.json?engine=google&q=${encodedUrl}&api_key=${serpApiKey}&num=1`);
      }

      const [microlinkResponse, serpResponse] = await Promise.allSettled([
          microlinkPromise, 
          serpPromise ? serpPromise : Promise.reject('No SerpApi Key')
      ]);

      let dataFound = false;
      let detailsFound = [];

      // Process Microlink Response
      if (microlinkResponse.status === 'fulfilled' && microlinkResponse.value.ok) {
        const json = await microlinkResponse.value.json();
        const data = json.data;

        if (data) {
            dataFound = true;
            // Name
            if (data.title) {
                let cleanName = data.title.split('|')[0].split(' : ')[0].trim();
                if (cleanName.length > 80) cleanName = cleanName.substring(0, 77) + '...';
                setName(cleanName);
                if (!detailsFound.includes("Name")) detailsFound.push("Name");
            }
            // Image
            if (data.image && data.image.url) {
                setImageUrl(data.image.url);
                detailsFound.push("Image");
            }
            // Platform
            if (data.publisher) {
                const lowerPub = data.publisher.toLowerCase();
                if (lowerPub.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPub.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPub.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPub.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
                else {
                    setPlatformType(EcommercePlatform.Other);
                    setCustomPlatform(data.publisher);
                }
            } else if (platform) {
                // Fallback
                const lowerPlat = platform.toLowerCase();
                if (lowerPlat.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPlat.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPlat.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPlat.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
            }

            // Microlink Price Fallback (Regex in description)
            const textsToCheck = [data.description, data.title];
            const priceRegex = /(?:₹|rs\.?|inr)\s*[:\.\-]?\s*(\d{1,3}(?:,\d{2,3})*(?:\.\d+)?)/i;
            for (const text of textsToCheck) {
                if (!text) continue;
                const match = text.match(priceRegex);
                if (match && match[1]) {
                    const extractedPrice = match[1].replace(/,/g, '');
                    if (extractedPrice.length === 4 && (extractedPrice.startsWith('202'))) continue;
                    setPrice(extractedPrice);
                    if (!detailsFound.includes("Price")) detailsFound.push("Price");
                    break;
                }
            }
        }
      }

      // Process SerpApi Response (Override Price if found, as it is more accurate)
      if (serpResponse.status === 'fulfilled' && serpResponse.value.ok) {
          const json = await serpResponse.value.json();
          const organic = json.organic_results?.[0];

          if (organic) {
            dataFound = true;
            let serpPrice = null;

            // Try rich snippet price
            if (organic.rich_snippet?.top?.detected_extensions?.price) {
                serpPrice = organic.rich_snippet.top.detected_extensions.price;
            } 
            // Try direct price
            else if (organic.price) {
                serpPrice = organic.price;
            }
            // Try snippet text regex
            else if (organic.snippet) {
                const match = organic.snippet.match(/(?:₹|rs\.?|inr)\s*[:\.\-]?\s*(\d{1,3}(?:,\d{2,3})*(?:\.\d+)?)/i);
                if (match && match[1]) serpPrice = match[1];
            }

            if (serpPrice) {
                // Clean price string
                const cleanPrice = serpPrice.toString().replace(/[^0-9.]/g, '');
                setPrice(cleanPrice);
                if (!detailsFound.includes("Price")) detailsFound.push("Price");
            }
          }
      }

      if (dataFound) {
        const msg = detailsFound.length > 0 
            ? `Auto-filled: ${detailsFound.join(', ')}` 
            : "Metadata found but no specific details extracted.";
        showToast(msg, "success");
      } else {
        throw new Error("No data found");
      }

    } catch (e: any) {
      console.error("Auto-fill failed", e);
      showToast(e.message || "Could not fetch details. Please fill manually.", "error");
    } finally {
      setIsFetching(false);
      onFetchChange?.(false, initialData?.id);
      setFetchStatus('');
    }
  };

  const validate = (): boolean => {
    const newErrors: ValidationErrors = {};
    let isValid = true;

    if (!name.trim()) {
      newErrors.name = t.validation.required;
      isValid = false;
    } else if (name.length > VALIDATION_LIMITS.NAME_MAX_LENGTH) {
      newErrors.name = t.validation.tooLong;
      isValid = false;
    }

    const numPrice = parseFloat(price);
    if (isNaN(numPrice) || numPrice < 0 || numPrice > VALIDATION_LIMITS.PRICE_MAX) {
      newErrors.price = t.validation.invalidPrice;
      isValid = false;
    }

    if (platformType === EcommercePlatform.Other && customPlatform.length > VALIDATION_LIMITS.PLATFORM_MAX_LENGTH) {
      newErrors.platform = t.validation.tooLong;
      isValid = false;
    }

    const validateUrl = (urlStr: string, field: 'link' | 'imageUrl') => {
        if (!urlStr.trim()) return;
        try {
            const url = new URL(urlStr);
            if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
                newErrors[field] = t.validation.invalidUrl;
                isValid = false;
            }
        } catch (e) {
            newErrors[field] = t.validation.invalidUrl;
            isValid = false;
        }
        if (urlStr.length > VALIDATION_LIMITS.URL_MAX_LENGTH) {
            newErrors[field] = t.validation.tooLong;
            isValid = false;
        }
    };

    validateUrl(link, 'link');
    validateUrl(imageUrl, 'imageUrl');

    if (notes.length > VALIDATION_LIMITS.NOTES_MAX_LENGTH) {
      newErrors.notes = t.validation.tooLong;
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    let finalPlatform = platformType as string;
    if (platformType === EcommercePlatform.Other) {
      finalPlatform = customPlatform.trim() || EcommercePlatform.Other;
    }

    const fixUrl = (u: string) => {
        let trimmed = u.trim();
        if (trimmed && !trimmed.startsWith('http://') && !trimmed.startsWith('https://')) {
            return `https://${trimmed}`;
        }
        return trimmed;
    };

    onSave({
      name: name.trim(),
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      platform: finalPlatform,
      notes: notes.trim(),
      link: fixUrl(link),
      imageUrl: fixUrl(imageUrl)
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/30 dark:bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="glass-panel w-full max-w-md max-h-[90vh] overflow-y-auto flex flex-col rounded-2xl shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-5 duration-300 border border-white/40 dark:border-white/10 bg-white/80 dark:bg-gray-900/80">

        <div className="flex items-center justify-between p-5 border-b border-black/5 dark:border-white/10">
          <h2 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600 dark:from-blue-400 dark:to-indigo-400">
            {initialData ? t.editItem : t.addItem}
          </h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
            <X size={20} className="text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 flex-1">

          {/* Link Field First to encourage Auto-fill */}
          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.link}</label>
             <div className="relative flex gap-2">
                <div className="relative flex-1 group">
                    <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/60 dark:bg-black/40 border border-black/10 dark:border-white/10 text-gray-500 group-focus-within:text-blue-500 group-focus-within:border-blue-500/50 transition-all duration-300 shadow-sm backdrop-blur-sm">
                        <Paperclip size={16} />
                    </div>
                    <input 
                      type="url"
                      value={link}
                      onChange={(e) => setLink(e.target.value)}
                      className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.link ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                      placeholder="https://www.amazon.in/..."
                    />
                </div>
                <button 
                  type="button"
                  onClick={handleAutoFill}
                  disabled={!link || isFetching}
                  className="px-3 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:shadow-lg transition-all flex items-center justify-center min-w-[3rem]"
                  title="Auto-fill details from Link"
                >
                  {isFetching ? <Loader2 size={18} className="animate-spin" /> : <Zap size={18} fill="currentColor" />}
                </button>
             </div>
             {errors.link && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.link}</p>}
             {isFetching && !errors.link && (
                <p className="mt-2 text-xs text-blue-600 dark:text-blue-400 flex items-center gap-2 animate-pulse font-medium">
                   <Loader2 size={12} className="animate-spin" /> 
                   {fetchStatus}
                </p>
             )}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.name}</label>
            <input 
              type="text" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.name ? 'border-red-500 focus:ring-red-500/50' : ''}`}
              placeholder="e.g., Noise Cancelling Headphones"
            />
            {errors.name && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.name}</p>}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.category}</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c} className="dark:bg-gray-900">{t.categories[c]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.price}</label>
              <input 
                type="number" 
                min="0"
                step="0.01"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.price ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                placeholder="0.00"
              />
              {errors.price && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.price}</p>}
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.platform}</label>
            <div className="grid grid-cols-2 gap-4">
              <select 
                value={platformType}
                onChange={(e) => setPlatformType(e.target.value as EcommercePlatform)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(EcommercePlatform).map(p => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.platforms[p]}</option>
                ))}
              </select>

              {platformType === EcommercePlatform.Other && (
                <div>
                    <input 
                    type="text"
                    value={customPlatform}
                    onChange={(e) => setCustomPlatform(e.target.value)}
                    className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all animate-in fade-in slide-in-from-left-2 ${errors.platform ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                    placeholder={t.labels.specifyPlatform}
                    />
                    {errors.platform && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.platform}</p>}
                </div>
              )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.status}</label>
              <select 
                value={status}
                onChange={(e) => setStatus(e.target.value as Status)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Status).map(s => (
                  <option key={s} value={s} className="dark:bg-gray-900">{t.statuses[s]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.priority}</label>
              <select 
                value={priority}
                onChange={(e) => setPriority(e.target.value as Priority)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {(Object.values(Priority) as Priority[]).map((p) => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.priorities[p]}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.imageUrl}</label>
             <div className="relative group">
                <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/50 dark:bg-black/20 border border-black/5 dark:border-white/5 text-gray-400 group-focus-within:text-blue-500 group-focus-within:border-blue-500/30 transition-all duration-300">
                    <ImageIcon size={16} />
                </div>
                <input 
                  type="url"
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                  className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.imageUrl ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                  placeholder="https://images.com/preview.jpg"
                />
             </div>
             {errors.imageUrl && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.imageUrl}</p>}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.notes}</label>
            <textarea 
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none resize-none transition-all ${errors.notes ? 'border-red-500 focus:ring-red-500/50' : ''}`}
            />
            {errors.notes && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.notes}</p>}
          </div>

          <div className="pt-2 flex gap-3">
             <Button type="button" variant="secondary" onClick={onClose} fullWidth className="glass-panel border-0 bg-gray-200/50 hover:bg-gray-200/80 dark:bg-gray-700/50 dark:hover:bg-gray-700/80">
              {t.labels.cancel}
             </Button>
             <Button type="submit" variant="primary" fullWidth className="shadow-lg shadow-blue-500/20">
              {t.labels.save}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, EcommercePlatform } from '../types';
import { VALIDATION_LIMITS, ALLOWED_PROTOCOLS } from '../constants';
import { useSettings } from '../context/SettingsContext';
import { useToast } from '../context/ToastContext';
import { Button } from './ui/Button';
import { X, Paperclip, AlertCircle, Image as ImageIcon, Sparkles, Loader2, Zap } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onFetchChange?: (isFetching: boolean, itemId?: string) => void;
}

interface ValidationErrors {
  name?: string;
  price?: string;
  platform?: string;
  link?: string;
  imageUrl?: string;
  notes?: string;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave, onFetchChange }) => {
  const { t, serpApiKey } = useSettings();
  const { showToast } = useToast();

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [platformType, setPlatformType] = useState<EcommercePlatform>(EcommercePlatform.Amazon);
  const [customPlatform, setCustomPlatform] = useState('');
  const [notes, setNotes] = useState('');
  const [link, setLink] = useState('');
  const [imageUrl, setImageUrl] = useState('');

  const [isFetching, setIsFetching] = useState(false);
  const [fetchStatus, setFetchStatus] = useState<string>('');

  const [errors, setErrors] = useState<ValidationErrors>({});

  const knownPlatforms = Object.values(EcommercePlatform) as string[];

  useEffect(() => {
    setErrors({});
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setNotes(initialData.notes || '');
      setLink(initialData.link || '');
      setImageUrl(initialData.imageUrl || '');

      const p = initialData.platform || EcommercePlatform.Other;
      if (knownPlatforms.includes(p) && p !== EcommercePlatform.Other) {
        setPlatformType(p as EcommercePlatform);
        setCustomPlatform('');
      } else {
        setPlatformType(EcommercePlatform.Other);
        setCustomPlatform(p === EcommercePlatform.Other ? '' : p);
      }

    } else {
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setPlatformType(EcommercePlatform.Amazon);
      setCustomPlatform('');
      setNotes('');
      setLink('');
      setImageUrl('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const detectPlatformFromUrl = (url: string): string => {
    try {
      const hostname = new URL(url).hostname.replace('www.', '');
      if (hostname.includes('amazon')) return 'Amazon';
      if (hostname.includes('flipkart')) return 'Flipkart';
      if (hostname.includes('myntra')) return 'Myntra';
      if (hostname.includes('ajio')) return 'Ajio';
      return hostname.charAt(0).toUpperCase() + hostname.slice(1).split('.')[0];
    } catch {
      return '';
    }
  };

  const extractPriceFromText = (text: string): number | null => {
    if (!text) return null;
    const cleanText = text.toLowerCase();

    // 1. Explicit patterns (High Confidence)
    // Matches: "price: ₹100", "mrp: rs 100", "₹100 (offer)"
    const explicitPattern = /(?:price|mrp|deal|offer|cost)\s*[:\-\.]?\s*(?:₹|rs\.?|inr)\s*([\d,]+(?:\.\d+)?)/i;
    const explicitMatch = cleanText.match(explicitPattern);
    if (explicitMatch && explicitMatch[1]) {
       return parseFloat(explicitMatch[1].replace(/,/g, ''));
    }

    // 2. Generic Currency pattern with negative lookbehind logic (Medium Confidence)
    // We iterate matches and check context to avoid "Save ₹500", "EMI ₹200", "Off ₹300"
    const currencyPattern = /(?:₹|rs\.?|inr)\s*[:\.\-]?\s*([\d,]+(?:\.\d+)?)/gi;
    const matches = [...text.matchAll(currencyPattern)];

    for (const match of matches) {
        const priceStr = match[1].replace(/,/g, '');
        const priceVal = parseFloat(priceStr);
        const index = match.index || 0;

        // Context check: Look at 25 chars before the match
        const context = text.substring(Math.max(0, index - 25), index).toLowerCase();

        // Skip if it looks like a discount or EMI
        if (context.includes('save') || context.includes('off') || context.includes('discount') || context.includes('emi') || context.includes('flat')) {
            continue;
        }

        // Basic sanity check for year-like numbers if they don't have explicit currency symbol (though regex enforces symbol)
        // If the number is exactly 2023, 2024, 2025 and context implies date? 
        // Our regex requires currency symbol, so "2024" alone won't match. "Rs 2024" will.

        return priceVal; // Return first valid match
    }

    return null;
  };

  const handleAutoFill = async () => {
    if (!link) return;

    try {
      new URL(link);
    } catch {
      setErrors({ ...errors, link: t.validation.invalidUrl });
      return;
    }

    setIsFetching(true);
    onFetchChange?.(true, initialData?.id);
    const platform = detectPlatformFromUrl(link);
    setFetchStatus(platform ? `Connecting to ${platform}...` : 'Fetching metadata...');

    try {
      const encodedUrl = encodeURIComponent(link);

      // 1. Microlink Request
      const microlinkPromise = fetch(`https://api.microlink.io/?url=${encodedUrl}&palette=true&audio=false&video=false`);

      // 2. SerpApi Request (if key exists)
      let serpPromise = null;
      if (serpApiKey) {
          // Using 'google' engine. 'google_product' requires product ID, 'google_shopping' often needs query not URL.
          // 'google' with q=URL finds the indexed page snippet which usually has the price.
          serpPromise = fetch(`https://serpapi.com/search.json?engine=google&q=${encodedUrl}&api_key=${serpApiKey}&num=1`);
      }

      const [microlinkResponse, serpResponse] = await Promise.allSettled([
          microlinkPromise, 
          serpPromise ? serpPromise : Promise.reject('No SerpApi Key')
      ]);

      let dataFound = false;
      let detailsFound: string[] = [];
      let foundPrice: number | null = null;

      // --- Process Microlink ---
      if (microlinkResponse.status === 'fulfilled' && microlinkResponse.value.ok) {
        const json = await microlinkResponse.value.json();
        const data = json.data;

        if (data) {
            dataFound = true;

            // Name
            if (data.title) {
                let cleanName = data.title.split('|')[0].split(' : ')[0].trim();
                if (cleanName.length > 80) cleanName = cleanName.substring(0, 77) + '...';
                setName(cleanName);
                if (!detailsFound.includes("Name")) detailsFound.push("Name");
            }

            // Image
            if (data.image && data.image.url) {
                setImageUrl(data.image.url);
                detailsFound.push("Image");
            }

            // Platform
            if (data.publisher) {
                const lowerPub = data.publisher.toLowerCase();
                if (lowerPub.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPub.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPub.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPub.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
                else {
                    setPlatformType(EcommercePlatform.Other);
                    setCustomPlatform(data.publisher);
                }
            } else if (platform) {
                const lowerPlat = platform.toLowerCase();
                if (lowerPlat.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPlat.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPlat.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPlat.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
            }

            // Try extracting price from Microlink Description/Title as fallback
            const textsToCheck = [data.description, data.title];
            for (const text of textsToCheck) {
                const p = extractPriceFromText(text);
                if (p !== null) {
                    foundPrice = p;
                    break;
                }
            }
        }
      }

      // --- Process SerpApi (Overrides Microlink price if found) ---
      if (serpResponse.status === 'fulfilled' && serpResponse.value.ok) {
          const json = await serpResponse.value.json();
          let serpPriceVal: number | null = null;

          // 1. Direct Product Result
          if (json.product_result?.price) {
             // Sometimes price is an object or string
             serpPriceVal = extractPriceFromText(json.product_result.price.toString());
          }
          // 2. Shopping Results (Inline)
          else if (json.shopping_results?.[0]?.price) {
             serpPriceVal = extractPriceFromText(json.shopping_results[0].price.toString());
          }
          // 3. Knowledge Graph
          else if (json.knowledge_graph?.price) {
             serpPriceVal = extractPriceFromText(json.knowledge_graph.price.toString());
          }
          // 4. Organic Result Rich Snippet (Most common for Amazon/Flipkart indexed pages)
          else if (json.organic_results?.[0]) {
              const organic = json.organic_results[0];

              // Try rich snippet detected extensions
              if (organic.rich_snippet?.top?.detected_extensions?.price) {
                  serpPriceVal = extractPriceFromText(organic.rich_snippet.top.detected_extensions.price.toString());
              }
              // Try price field
              else if (organic.price) {
                  serpPriceVal = extractPriceFromText(organic.price.toString());
              }
              // Try parsing the snippet text
              else if (organic.snippet) {
                  serpPriceVal = extractPriceFromText(organic.snippet);
              }
          }

          if (serpPriceVal !== null) {
              foundPrice = serpPriceVal;
              dataFound = true; // SerpApi finding data counts
          }
      }

      // Final Price Update
      if (foundPrice !== null) {
          setPrice(foundPrice.toString());
          if (!detailsFound.includes("Price")) detailsFound.push("Price");
      }

      if (dataFound) {
        const msg = detailsFound.length > 0 
            ? `Auto-filled: ${detailsFound.join(', ')}` 
            : "Metadata found but no specific details extracted.";
        showToast(msg, "success");
      } else {
        throw new Error("No data found");
      }

    } catch (e: any) {
      console.error("Auto-fill failed", e);
      showToast(e.message || "Could not fetch details. Please fill manually.", "error");
    } finally {
      setIsFetching(false);
      onFetchChange?.(false, initialData?.id);
      setFetchStatus('');
    }
  };

  const validate = (): boolean => {
    const newErrors: ValidationErrors = {};
    let isValid = true;

    if (!name.trim()) {
      newErrors.name = t.validation.required;
      isValid = false;
    } else if (name.length > VALIDATION_LIMITS.NAME_MAX_LENGTH) {
      newErrors.name = t.validation.tooLong;
      isValid = false;
    }

    const numPrice = parseFloat(price);
    if (isNaN(numPrice) || numPrice < 0 || numPrice > VALIDATION_LIMITS.PRICE_MAX) {
      newErrors.price = t.validation.invalidPrice;
      isValid = false;
    }

    if (platformType === EcommercePlatform.Other && customPlatform.length > VALIDATION_LIMITS.PLATFORM_MAX_LENGTH) {
      newErrors.platform = t.validation.tooLong;
      isValid = false;
    }

    const validateUrl = (urlStr: string, field: 'link' | 'imageUrl') => {
        if (!urlStr.trim()) return;
        try {
            const url = new URL(urlStr);
            if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
                newErrors[field] = t.validation.invalidUrl;
                isValid = false;
            }
        } catch (e) {
            newErrors[field] = t.validation.invalidUrl;
            isValid = false;
        }
        if (urlStr.length > VALIDATION_LIMITS.URL_MAX_LENGTH) {
            newErrors[field] = t.validation.tooLong;
            isValid = false;
        }
    };

    validateUrl(link, 'link');
    validateUrl(imageUrl, 'imageUrl');

    if (notes.length > VALIDATION_LIMITS.NOTES_MAX_LENGTH) {
      newErrors.notes = t.validation.tooLong;
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    let finalPlatform = platformType as string;
    if (platformType === EcommercePlatform.Other) {
      finalPlatform = customPlatform.trim() || EcommercePlatform.Other;
    }

    const fixUrl = (u: string) => {
        let trimmed = u.trim();
        if (trimmed && !trimmed.startsWith('http://') && !trimmed.startsWith('https://')) {
            return `https://${trimmed}`;
        }
        return trimmed;
    };

    onSave({
      name: name.trim(),
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      platform: finalPlatform,
      notes: notes.trim(),
      link: fixUrl(link),
      imageUrl: fixUrl(imageUrl)
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/30 dark:bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="glass-panel w-full max-w-md max-h-[90vh] overflow-y-auto flex flex-col rounded-2xl shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-5 duration-300 border border-white/40 dark:border-white/10 bg-white/80 dark:bg-gray-900/80">

        <div className="flex items-center justify-between p-5 border-b border-black/5 dark:border-white/10">
          <h2 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600 dark:from-blue-400 dark:to-indigo-400">
            {initialData ? t.editItem : t.addItem}
          </h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
            <X size={20} className="text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 flex-1">

          {/* Link Field First to encourage Auto-fill */}
          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.link}</label>
             <div className="relative flex gap-2">
                <div className="relative flex-1 group">
                    <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/60 dark:bg-black/40 border border-black/10 dark:border-white/10 text-gray-500 group-focus-within:text-blue-500 group-focus-within:border-blue-500/50 transition-all duration-300 shadow-sm backdrop-blur-sm">
                        <Paperclip size={16} />
                    </div>
                    <input 
                      type="url"
                      value={link}
                      onChange={(e) => setLink(e.target.value)}
                      className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.link ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                      placeholder="https://www.amazon.in/..."
                    />
                </div>
                <button 
                  type="button"
                  onClick={handleAutoFill}
                  disabled={!link || isFetching}
                  className="px-3 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:shadow-lg transition-all flex items-center justify-center min-w-[3rem]"
                  title="Auto-fill details from Link"
                >
                  {isFetching ? <Loader2 size={18} className="animate-spin" /> : <Zap size={18} fill="currentColor" />}
                </button>
             </div>
             {errors.link && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.link}</p>}
             {isFetching && !errors.link && (
                <p className="mt-2 text-xs text-blue-600 dark:text-blue-400 flex items-center gap-2 animate-pulse font-medium">
                   <Loader2 size={12} className="animate-spin" /> 
                   {fetchStatus}
                </p>
             )}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.name}</label>
            <input 
              type="text" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.name ? 'border-red-500 focus:ring-red-500/50' : ''}`}
              placeholder="e.g., Noise Cancelling Headphones"
            />
            {errors.name && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.name}</p>}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.category}</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c} className="dark:bg-gray-900">{t.categories[c]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.price}</label>
              <input 
                type="number" 
                min="0"
                step="0.01"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.price ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                placeholder="0.00"
              />
              {errors.price && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.price}</p>}
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.platform}</label>
            <div className="grid grid-cols-2 gap-4">
              <select 
                value={platformType}
                onChange={(e) => setPlatformType(e.target.value as EcommercePlatform)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(EcommercePlatform).map(p => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.platforms[p]}</option>
                ))}
              </select>

              {platformType === EcommercePlatform.Other && (
                <div>
                    <input 
                    type="text"
                    value={customPlatform}
                    onChange={(e) => setCustomPlatform(e.target.value)}
                    className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all animate-in fade-in slide-in-from-left-2 ${errors.platform ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                    placeholder={t.labels.specifyPlatform}
                    />
                    {errors.platform && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.platform}</p>}
                </div>
              )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.status}</label>
              <select 
                value={status}
                onChange={(e) => setStatus(e.target.value as Status)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Status).map(s => (
                  <option key={s} value={s} className="dark:bg-gray-900">{t.statuses[s]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.priority}</label>
              <select 
                value={priority}
                onChange={(e) => setPriority(e.target.value as Priority)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {(Object.values(Priority) as Priority[]).map((p) => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.priorities[p]}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.imageUrl}</label>
             <div className="relative group">
                <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/50 dark:bg-black/20 border border-black/5 dark:border-white/5 text-gray-400 group-focus-within:text-blue-500 group-focus-within:border-blue-500/30 transition-all duration-300">
                    <ImageIcon size={16} />
                </div>
                <input 
                  type="url"
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                  className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.imageUrl ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                  placeholder="https://images.com/preview.jpg"
                />
             </div>
             {errors.imageUrl && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.imageUrl}</p>}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.notes}</label>
            <textarea 
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none resize-none transition-all ${errors.notes ? 'border-red-500 focus:ring-red-500/50' : ''}`}
            />
            {errors.notes && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.notes}</p>}
          </div>

          <div className="pt-2 flex gap-3">
             <Button type="button" variant="secondary" onClick={onClose} fullWidth className="glass-panel border-0 bg-gray-200/50 hover:bg-gray-200/80 dark:bg-gray-700/50 dark:hover:bg-gray-700/80">
              {t.labels.cancel}
             </Button>
             <Button type="submit" variant="primary" fullWidth className="shadow-lg shadow-blue-500/20">
              {t.labels.save}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, EcommercePlatform } from '../types';
import { VALIDATION_LIMITS, ALLOWED_PROTOCOLS } from '../constants';
import { useSettings } from '../context/SettingsContext';
import { useToast } from '../context/ToastContext';
import { Button } from './ui/Button';
import { X, Paperclip, AlertCircle, Image as ImageIcon, Sparkles, Loader2, Zap } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onFetchChange?: (isFetching: boolean, itemId?: string) => void;
}

interface ValidationErrors {
  name?: string;
  price?: string;
  platform?: string;
  link?: string;
  imageUrl?: string;
  notes?: string;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave, onFetchChange }) => {
  const { t, serpApiKey } = useSettings();
  const { showToast } = useToast();

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [platformType, setPlatformType] = useState<EcommercePlatform>(EcommercePlatform.Amazon);
  const [customPlatform, setCustomPlatform] = useState('');
  const [notes, setNotes] = useState('');
  const [link, setLink] = useState('');
  const [imageUrl, setImageUrl] = useState('');

  const [isFetching, setIsFetching] = useState(false);
  const [fetchStatus, setFetchStatus] = useState<string>('');

  const [errors, setErrors] = useState<ValidationErrors>({});

  const knownPlatforms = Object.values(EcommercePlatform) as string[];

  useEffect(() => {
    setErrors({});
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setNotes(initialData.notes || '');
      setLink(initialData.link || '');
      setImageUrl(initialData.imageUrl || '');

      const p = initialData.platform || EcommercePlatform.Other;
      if (knownPlatforms.includes(p) && p !== EcommercePlatform.Other) {
        setPlatformType(p as EcommercePlatform);
        setCustomPlatform('');
      } else {
        setPlatformType(EcommercePlatform.Other);
        setCustomPlatform(p === EcommercePlatform.Other ? '' : p);
      }

    } else {
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setPlatformType(EcommercePlatform.Amazon);
      setCustomPlatform('');
      setNotes('');
      setLink('');
      setImageUrl('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const detectPlatformFromUrl = (url: string): string => {
    try {
      const hostname = new URL(url).hostname.replace('www.', '');
      if (hostname.includes('amazon')) return 'Amazon';
      if (hostname.includes('flipkart')) return 'Flipkart';
      if (hostname.includes('myntra')) return 'Myntra';
      if (hostname.includes('ajio')) return 'Ajio';
      return hostname.charAt(0).toUpperCase() + hostname.slice(1).split('.')[0];
    } catch {
      return '';
    }
  };

  /**
   * Helper to parse price from string.
   * @param text The text to search
   * @param requireSymbol If true, requires ₹/Rs/INR etc. If false, accepts pure numbers (useful for API fields).
   */
  const extractPriceFromText = (text: string, requireSymbol: boolean = true): number | null => {
    if (!text) return null;
    const cleanText = text.toLowerCase().trim();

    // 0. Direct Number check (if symbol not required)
    if (!requireSymbol) {
        // Remove currency symbols and commas, check if it is a valid number
        const numeric = cleanText.replace(/[^\d.]/g, '');
        const val = parseFloat(numeric);
        if (!isNaN(val) && val > 0) return val;
    }

    // 1. Explicit patterns (High Confidence)
    // Matches: "price: ₹100", "mrp: rs 100", "₹100 (offer)"
    const explicitPattern = /(?:price|mrp|deal|offer|cost)\s*[:\-\.]?\s*(?:₹|rs\.?|inr)?\s*([\d,]+(?:\.\d+)?)/i;
    const explicitMatch = cleanText.match(explicitPattern);
    if (explicitMatch && explicitMatch[1]) {
       return parseFloat(explicitMatch[1].replace(/,/g, ''));
    }

    // 2. Generic Currency pattern with negative lookbehind logic (Medium Confidence)
    // We iterate matches and check context to avoid "Save ₹500", "EMI ₹200", "Off ₹300"
    const currencyPattern = /(?:₹|rs\.?|inr)\s*[:\.\-]?\s*([\d,]+(?:\.\d+)?)/gi;
    const matches = [...text.matchAll(currencyPattern)];

    for (const match of matches) {
        const priceStr = match[1].replace(/,/g, '');
        const priceVal = parseFloat(priceStr);
        const index = match.index || 0;

        // Context check: Look at 25 chars before the match
        const context = text.substring(Math.max(0, index - 25), index).toLowerCase();

        // Skip if it looks like a discount or EMI
        if (context.includes('save') || context.includes('off') || context.includes('discount') || context.includes('emi') || context.includes('flat')) {
            continue;
        }

        return priceVal; // Return first valid match
    }

    return null;
  };

  const handleAutoFill = async () => {
    if (!link) return;

    try {
      new URL(link);
    } catch {
      setErrors({ ...errors, link: t.validation.invalidUrl });
      return;
    }

    setIsFetching(true);
    onFetchChange?.(true, initialData?.id);
    const platform = detectPlatformFromUrl(link);
    setFetchStatus(platform ? `Connecting to ${platform}...` : 'Fetching metadata...');

    try {
      const encodedUrl = encodeURIComponent(link);

      // 1. Microlink Request
      const microlinkPromise = fetch(`https://api.microlink.io/?url=${encodedUrl}&palette=true&audio=false&video=false`);

      // 2. SerpApi Request (if key exists)
      let serpPromise = null;
      if (serpApiKey) {
          // 'google' engine with q=URL finds the indexed page snippet which usually has the price.
          serpPromise = fetch(`https://serpapi.com/search.json?engine=google&q=${encodedUrl}&api_key=${serpApiKey}&num=1`);
      }

      const [microlinkResponse, serpResponse] = await Promise.allSettled([
          microlinkPromise, 
          serpPromise ? serpPromise : Promise.reject('No SerpApi Key')
      ]);

      let dataFound = false;
      let detailsFound: string[] = [];
      let foundPrice: number | null = null;

      // --- Process Microlink ---
      if (microlinkResponse.status === 'fulfilled' && microlinkResponse.value.ok) {
        const json = await microlinkResponse.value.json();
        const data = json.data;

        if (data) {
            dataFound = true;

            // Name
            if (data.title) {
                let cleanName = data.title.split('|')[0].split(' : ')[0].trim();
                if (cleanName.length > 80) cleanName = cleanName.substring(0, 77) + '...';
                setName(cleanName);
                if (!detailsFound.includes("Name")) detailsFound.push("Name");
            }

            // Image
            if (data.image && data.image.url) {
                setImageUrl(data.image.url);
                detailsFound.push("Image");
            }

            // Platform
            if (data.publisher) {
                const lowerPub = data.publisher.toLowerCase();
                if (lowerPub.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPub.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPub.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPub.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
                else {
                    setPlatformType(EcommercePlatform.Other);
                    setCustomPlatform(data.publisher);
                }
            } else if (platform) {
                const lowerPlat = platform.toLowerCase();
                if (lowerPlat.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPlat.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPlat.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPlat.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
            }

            // Try extracting price from Microlink Description/Title as fallback
            const textsToCheck = [data.description, data.title];
            for (const text of textsToCheck) {
                const p = extractPriceFromText(text, true); // require symbol for text scraping
                if (p !== null) {
                    foundPrice = p;
                    break;
                }
            }
        }
      }

      // --- Process SerpApi (Overrides Microlink price if found) ---
      if (serpResponse.status === 'fulfilled' && serpResponse.value.ok) {
          const json = await serpResponse.value.json();
          let serpPriceVal: number | null = null;

          // 1. Direct Product Result (Usually numeric or clean string)
          if (json.product_result?.price) {
             serpPriceVal = extractPriceFromText(json.product_result.price.toString(), false);
          }
          // 2. Shopping Results (Inline)
          else if (json.shopping_results?.[0]?.price) {
             serpPriceVal = extractPriceFromText(json.shopping_results[0].price.toString(), false);
          }
          // 3. Knowledge Graph
          else if (json.knowledge_graph?.price) {
             serpPriceVal = extractPriceFromText(json.knowledge_graph.price.toString(), false);
          }
          // 4. Organic Result Rich Snippet (Most common for Amazon/Flipkart indexed pages)
          else if (json.organic_results?.[0]) {
              const organic = json.organic_results[0];

              // Try rich snippet detected extensions - often just a number in JSON
              if (organic.rich_snippet?.top?.detected_extensions?.price) {
                  serpPriceVal = extractPriceFromText(organic.rich_snippet.top.detected_extensions.price.toString(), false);
              }
              // Try price field
              else if (organic.price) {
                  serpPriceVal = extractPriceFromText(organic.price.toString(), false);
              }
              // Try parsing the snippet text (requires symbol here as it is unstructured text)
              else if (organic.snippet) {
                  serpPriceVal = extractPriceFromText(organic.snippet, true);
              }
          }

          if (serpPriceVal !== null) {
              foundPrice = serpPriceVal;
              dataFound = true; // SerpApi finding data counts
          }
      }

      // Final Price Update
      if (foundPrice !== null) {
          setPrice(foundPrice.toString());
          if (!detailsFound.includes("Price")) detailsFound.push("Price");
      }

      if (dataFound) {
        const msg = detailsFound.length > 0 
            ? `Auto-filled: ${detailsFound.join(', ')}` 
            : "Metadata found but no specific details extracted.";
        showToast(msg, "success");
      } else {
        throw new Error("No data found");
      }

    } catch (e: any) {
      console.error("Auto-fill failed", e);
      showToast(e.message || "Could not fetch details. Please fill manually.", "error");
    } finally {
      setIsFetching(false);
      onFetchChange?.(false, initialData?.id);
      setFetchStatus('');
    }
  };

  const validate = (): boolean => {
    const newErrors: ValidationErrors = {};
    let isValid = true;

    if (!name.trim()) {
      newErrors.name = t.validation.required;
      isValid = false;
    } else if (name.length > VALIDATION_LIMITS.NAME_MAX_LENGTH) {
      newErrors.name = t.validation.tooLong;
      isValid = false;
    }

    const numPrice = parseFloat(price);
    // Allow empty price or 0, but if something is typed it must be valid.
    // However, the form usually requires a valid price if you want to be strict.
    // Based on the screenshot, "Invalid price" error happens. 
    // If price is empty string, numPrice is NaN.
    if (price !== '' && (isNaN(numPrice) || numPrice < 0 || numPrice > VALIDATION_LIMITS.PRICE_MAX)) {
      newErrors.price = t.validation.invalidPrice;
      isValid = false;
    }

    if (platformType === EcommercePlatform.Other && customPlatform.length > VALIDATION_LIMITS.PLATFORM_MAX_LENGTH) {
      newErrors.platform = t.validation.tooLong;
      isValid = false;
    }

    const validateUrl = (urlStr: string, field: 'link' | 'imageUrl') => {
        if (!urlStr.trim()) return;
        try {
            const url = new URL(urlStr);
            if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
                newErrors[field] = t.validation.invalidUrl;
                isValid = false;
            }
        } catch (e) {
            newErrors[field] = t.validation.invalidUrl;
            isValid = false;
        }
        if (urlStr.length > VALIDATION_LIMITS.URL_MAX_LENGTH) {
            newErrors[field] = t.validation.tooLong;
            isValid = false;
        }
    };

    validateUrl(link, 'link');
    validateUrl(imageUrl, 'imageUrl');

    if (notes.length > VALIDATION_LIMITS.NOTES_MAX_LENGTH) {
      newErrors.notes = t.validation.tooLong;
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    let finalPlatform = platformType as string;
    if (platformType === EcommercePlatform.Other) {
      finalPlatform = customPlatform.trim() || EcommercePlatform.Other;
    }

    const fixUrl = (u: string) => {
        let trimmed = u.trim();
        if (trimmed && !trimmed.startsWith('http://') && !trimmed.startsWith('https://')) {
            return `https://${trimmed}`;
        }
        return trimmed;
    };

    onSave({
      name: name.trim(),
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      platform: finalPlatform,
      notes: notes.trim(),
      link: fixUrl(link),
      imageUrl: fixUrl(imageUrl)
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/30 dark:bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="glass-panel w-full max-w-md max-h-[90vh] overflow-y-auto flex flex-col rounded-2xl shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-5 duration-300 border border-white/40 dark:border-white/10 bg-white/80 dark:bg-gray-900/80">

        <div className="flex items-center justify-between p-5 border-b border-black/5 dark:border-white/10">
          <h2 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600 dark:from-blue-400 dark:to-indigo-400">
            {initialData ? t.editItem : t.addItem}
          </h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
            <X size={20} className="text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 flex-1">

          {/* Link Field First to encourage Auto-fill */}
          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.link}</label>
             <div className="relative flex gap-2">
                <div className="relative flex-1 group">
                    <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/60 dark:bg-black/40 border border-black/10 dark:border-white/10 text-gray-500 group-focus-within:text-blue-500 group-focus-within:border-blue-500/50 transition-all duration-300 shadow-sm backdrop-blur-sm">
                        <Paperclip size={16} />
                    </div>
                    <input 
                      type="url"
                      value={link}
                      onChange={(e) => setLink(e.target.value)}
                      className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.link ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                      placeholder="https://www.amazon.in/..."
                    />
                </div>
                <button 
                  type="button"
                  onClick={handleAutoFill}
                  disabled={!link || isFetching}
                  className="px-3 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:shadow-lg transition-all flex items-center justify-center min-w-[3rem]"
                  title="Auto-fill details from Link"
                >
                  {isFetching ? <Loader2 size={18} className="animate-spin" /> : <Zap size={18} fill="currentColor" />}
                </button>
             </div>
             {errors.link && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.link}</p>}
             {isFetching && !errors.link && (
                <p className="mt-2 text-xs text-blue-600 dark:text-blue-400 flex items-center gap-2 animate-pulse font-medium">
                   <Loader2 size={12} className="animate-spin" /> 
                   {fetchStatus}
                </p>
             )}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.name}</label>
            <input 
              type="text" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.name ? 'border-red-500 focus:ring-red-500/50' : ''}`}
              placeholder="e.g., Noise Cancelling Headphones"
            />
            {errors.name && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.name}</p>}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.category}</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c} className="dark:bg-gray-900">{t.categories[c]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.price}</label>
              <input 
                type="number" 
                min="0"
                step="0.01"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.price ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                placeholder="0.00"
              />
              {errors.price && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.price}</p>}
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.platform}</label>
            <div className="grid grid-cols-2 gap-4">
              <select 
                value={platformType}
                onChange={(e) => setPlatformType(e.target.value as EcommercePlatform)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(EcommercePlatform).map(p => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.platforms[p]}</option>
                ))}
              </select>

              {platformType === EcommercePlatform.Other && (
                <div>
                    <input 
                    type="text"
                    value={customPlatform}
                    onChange={(e) => setCustomPlatform(e.target.value)}
                    className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all animate-in fade-in slide-in-from-left-2 ${errors.platform ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                    placeholder={t.labels.specifyPlatform}
                    />
                    {errors.platform && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.platform}</p>}
                </div>
              )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.status}</label>
              <select 
                value={status}
                onChange={(e) => setStatus(e.target.value as Status)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Status).map(s => (
                  <option key={s} value={s} className="dark:bg-gray-900">{t.statuses[s]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.priority}</label>
              <select 
                value={priority}
                onChange={(e) => setPriority(e.target.value as Priority)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {(Object.values(Priority) as Priority[]).map((p) => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.priorities[p]}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.imageUrl}</label>
             <div className="relative group">
                <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/50 dark:bg-black/20 border border-black/5 dark:border-white/5 text-gray-400 group-focus-within:text-blue-500 group-focus-within:border-blue-500/30 transition-all duration-300">
                    <ImageIcon size={16} />
                </div>
                <input 
                  type="url"
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                  className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.imageUrl ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                  placeholder="https://images.com/preview.jpg"
                />
             </div>
             {errors.imageUrl && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.imageUrl}</p>}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.notes}</label>
            <textarea 
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none resize-none transition-all ${errors.notes ? 'border-red-500 focus:ring-red-500/50' : ''}`}
            />
            {errors.notes && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.notes}</p>}
          </div>

          <div className="pt-2 flex gap-3">
             <Button type="button" variant="secondary" onClick={onClose} fullWidth className="glass-panel border-0 bg-gray-200/50 hover:bg-gray-200/80 dark:bg-gray-700/50 dark:hover:bg-gray-700/80">
              {t.labels.cancel}
             </Button>
             <Button type="submit" variant="primary" fullWidth className="shadow-lg shadow-blue-500/20">
              {t.labels.save}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, EcommercePlatform } from '../types';
import { VALIDATION_LIMITS, ALLOWED_PROTOCOLS } from '../constants';
import { useSettings } from '../context/SettingsContext';
import { useToast } from '../context/ToastContext';
import { Button } from './ui/Button';
import { X, Paperclip, AlertCircle, Image as ImageIcon, Loader2, Zap } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onFetchChange?: (isFetching: boolean, itemId?: string) => void;
}

interface ValidationErrors {
  name?: string;
  price?: string;
  platform?: string;
  link?: string;
  imageUrl?: string;
  notes?: string;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave, onFetchChange }) => {
  const { t, serpApiKey } = useSettings();
  const { showToast } = useToast();

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [platformType, setPlatformType] = useState<EcommercePlatform>(EcommercePlatform.Amazon);
  const [customPlatform, setCustomPlatform] = useState('');
  const [notes, setNotes] = useState('');
  const [link, setLink] = useState('');
  const [imageUrl, setImageUrl] = useState('');

  const [isFetching, setIsFetching] = useState(false);
  const [fetchStatus, setFetchStatus] = useState<string>('');

  const [errors, setErrors] = useState<ValidationErrors>({});

  const knownPlatforms = Object.values(EcommercePlatform) as string[];

  useEffect(() => {
    setErrors({});
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setNotes(initialData.notes || '');
      setLink(initialData.link || '');
      setImageUrl(initialData.imageUrl || '');

      const p = initialData.platform || EcommercePlatform.Other;
      if (knownPlatforms.includes(p) && p !== EcommercePlatform.Other) {
        setPlatformType(p as EcommercePlatform);
        setCustomPlatform('');
      } else {
        setPlatformType(EcommercePlatform.Other);
        setCustomPlatform(p === EcommercePlatform.Other ? '' : p);
      }

    } else {
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setPlatformType(EcommercePlatform.Amazon);
      setCustomPlatform('');
      setNotes('');
      setLink('');
      setImageUrl('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const detectPlatformFromUrl = (url: string): string => {
    try {
      const hostname = new URL(url).hostname.replace('www.', '');
      if (hostname.includes('amazon')) return 'Amazon';
      if (hostname.includes('flipkart')) return 'Flipkart';
      if (hostname.includes('myntra')) return 'Myntra';
      if (hostname.includes('ajio')) return 'Ajio';
      return hostname.charAt(0).toUpperCase() + hostname.slice(1).split('.')[0];
    } catch {
      return '';
    }
  };

  /**
   * Helper to parse price from string.
   * Supports: ₹, Rs, INR, $, USD, €, EUR, £, GBP
   */
  const extractPriceFromText = (text: string, requireSymbol: boolean = true): number | null => {
    if (!text) return null;
    const cleanText = text.toLowerCase().trim();

    // 0. Direct Number check (if symbol not required)
    if (!requireSymbol) {
        // Remove currency symbols and commas, check if it is a valid number
        // We preserve dots for decimals
        const numeric = cleanText.replace(/[^\d.]/g, '');
        const val = parseFloat(numeric);
        if (!isNaN(val) && val > 0) return val;
    }

    // 1. Explicit patterns (High Confidence)
    // Matches: "price: ₹100", "mrp: rs 100", "₹100 (offer)"
    const explicitPattern = /(?:price|mrp|deal|offer|cost)\s*[:\-\.]?\s*(?:₹|rs\.?|inr|\$|usd|€|eur|£|gbp)?\s*([\d,]+(?:\.\d+)?)/i;
    const explicitMatch = cleanText.match(explicitPattern);
    if (explicitMatch && explicitMatch[1]) {
       return parseFloat(explicitMatch[1].replace(/,/g, ''));
    }

    // 2. Generic Currency pattern
    const currencyPattern = /(?:₹|rs\.?|inr|\$|usd|€|eur|£|gbp)\s*[:\.\-]?\s*([\d,]+(?:\.\d+)?)/gi;
    const matches = [...text.matchAll(currencyPattern)];

    for (const match of matches) {
        const priceStr = match[1].replace(/,/g, '');
        const priceVal = parseFloat(priceStr);
        const index = match.index || 0;

        // Context check: Look at 25 chars before the match to avoid "Save ₹...", "Off ₹..."
        const context = text.substring(Math.max(0, index - 25), index).toLowerCase();

        if (context.includes('save') || context.includes('off') || context.includes('discount') || context.includes('emi') || context.includes('flat')) {
            continue;
        }

        return priceVal;
    }

    return null;
  };

  const handleAutoFill = async () => {
    if (!link) return;

    try {
      new URL(link);
    } catch {
      setErrors({ ...errors, link: t.validation.invalidUrl });
      return;
    }

    setIsFetching(true);
    onFetchChange?.(true, initialData?.id);
    const platform = detectPlatformFromUrl(link);
    setFetchStatus(platform ? `Connecting to ${platform}...` : 'Fetching metadata...');

    let dataFound = false;
    let detailsFound: string[] = [];
    let foundPrice: number | null = null;
    let resolvedUrl = link;

    try {
      const encodedUrl = encodeURIComponent(link);

      // STEP 1: Fetch Microlink (Resolves redirects & gets basic meta)
      const microlinkRes = await fetch(`https://api.microlink.io/?url=${encodedUrl}&palette=true&audio=false&video=false`);

      if (microlinkRes.ok) {
        const json = await microlinkRes.json();
        const data = json.data;

        if (data) {
            dataFound = true;

            // Capture resolved URL (Important for Short Links like amzn.in)
            if (data.url && data.url !== link) {
                resolvedUrl = data.url;
            }

            // Name
            if (data.title) {
                let cleanName = data.title.split('|')[0].split(' : ')[0].trim();
                if (cleanName.length > 80) cleanName = cleanName.substring(0, 77) + '...';
                setName(cleanName);
                if (!detailsFound.includes("Name")) detailsFound.push("Name");
            }

            // Image
            if (data.image && data.image.url) {
                setImageUrl(data.image.url);
                detailsFound.push("Image");
            }

            // Platform Detection
            if (data.publisher) {
                const lowerPub = data.publisher.toLowerCase();
                if (lowerPub.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPub.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPub.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPub.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
                else {
                    setPlatformType(EcommercePlatform.Other);
                    setCustomPlatform(data.publisher);
                }
            } else {
                 const p = detectPlatformFromUrl(resolvedUrl);
                 if (p) {
                    if (p === 'Amazon') setPlatformType(EcommercePlatform.Amazon);
                    else if (p === 'Flipkart') setPlatformType(EcommercePlatform.Flipkart);
                    else setPlatformType(EcommercePlatform.Other); 
                 }
            }

            // Microlink Price Fallback
            const textsToCheck = [data.description, data.title];
            for (const text of textsToCheck) {
                const p = extractPriceFromText(text, true); 
                if (p !== null) {
                    foundPrice = p;
                    break;
                }
            }
        }
      }

      // STEP 2: Fetch SerpApi using the RESOLVED URL (if available)
      // We chain this because we want to search the "long" url for better results.
      if (serpApiKey) {
          setFetchStatus('Checking price sources...');

          // Use resolved URL from Microlink if available, otherwise original
          const searchUrl = encodeURIComponent(resolvedUrl);
          const serpRes = await fetch(`https://serpapi.com/search.json?engine=google&q=${searchUrl}&api_key=${serpApiKey}&num=1`);

          if (serpRes.ok) {
              const json = await serpRes.json();
              let serpPriceVal: number | null = null;

              // 1. Product Result (Direct)
              if (json.product_result?.price) {
                 serpPriceVal = extractPriceFromText(json.product_result.price.toString(), false);
              }
              // 2. Shopping Results
              else if (json.shopping_results?.[0]?.price) {
                 serpPriceVal = extractPriceFromText(json.shopping_results[0].price.toString(), false);
              }
              // 3. Knowledge Graph
              else if (json.knowledge_graph?.price) {
                 serpPriceVal = extractPriceFromText(json.knowledge_graph.price.toString(), false);
              }
              // 4. Organic Result Rich Snippet
              else if (json.organic_results?.[0]) {
                  const organic = json.organic_results[0];
                  if (organic.rich_snippet?.top?.detected_extensions?.price) {
                      serpPriceVal = extractPriceFromText(organic.rich_snippet.top.detected_extensions.price.toString(), false);
                  }
                  else if (organic.price) {
                      serpPriceVal = extractPriceFromText(organic.price.toString(), false);
                  }
                  else if (organic.snippet) {
                      serpPriceVal = extractPriceFromText(organic.snippet, true);
                  }
              }

              if (serpPriceVal !== null) {
                  foundPrice = serpPriceVal;
                  dataFound = true;
              }
          }
      }

      // Final Price Update
      if (foundPrice !== null) {
          setPrice(foundPrice.toString());
          if (!detailsFound.includes("Price")) detailsFound.push("Price");
      }

      if (dataFound) {
        const msg = detailsFound.length > 0 
            ? `Auto-filled: ${detailsFound.join(', ')}` 
            : "Metadata found but price was hidden.";
        showToast(msg, detailsFound.length > 0 ? "success" : "success"); // Changed to success to not alarm user, just info
      } else {
        throw new Error("No data found");
      }

    } catch (e: any) {
      console.error("Auto-fill failed", e);
      showToast(e.message || "Could not fetch details. Please fill manually.", "error");
    } finally {
      setIsFetching(false);
      onFetchChange?.(false, initialData?.id);
      setFetchStatus('');
    }
  };

  const validate = (): boolean => {
    const newErrors: ValidationErrors = {};
    let isValid = true;

    if (!name.trim()) {
      newErrors.name = t.validation.required;
      isValid = false;
    } else if (name.length > VALIDATION_LIMITS.NAME_MAX_LENGTH) {
      newErrors.name = t.validation.tooLong;
      isValid = false;
    }

    // Price validation: Allow empty (0), but if typed, must be valid.
    const numPrice = parseFloat(price);
    if (price !== '' && (isNaN(numPrice) || numPrice < 0 || numPrice > VALIDATION_LIMITS.PRICE_MAX)) {
      newErrors.price = t.validation.invalidPrice;
      isValid = false;
    }

    if (platformType === EcommercePlatform.Other && customPlatform.length > VALIDATION_LIMITS.PLATFORM_MAX_LENGTH) {
      newErrors.platform = t.validation.tooLong;
      isValid = false;
    }

    const validateUrl = (urlStr: string, field: 'link' | 'imageUrl') => {
        if (!urlStr.trim()) return;
        try {
            const url = new URL(urlStr);
            if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
                newErrors[field] = t.validation.invalidUrl;
                isValid = false;
            }
        } catch (e) {
            newErrors[field] = t.validation.invalidUrl;
            isValid = false;
        }
        if (urlStr.length > VALIDATION_LIMITS.URL_MAX_LENGTH) {
            newErrors[field] = t.validation.tooLong;
            isValid = false;
        }
    };

    validateUrl(link, 'link');
    validateUrl(imageUrl, 'imageUrl');

    if (notes.length > VALIDATION_LIMITS.NOTES_MAX_LENGTH) {
      newErrors.notes = t.validation.tooLong;
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    let finalPlatform = platformType as string;
    if (platformType === EcommercePlatform.Other) {
      finalPlatform = customPlatform.trim() || EcommercePlatform.Other;
    }

    const fixUrl = (u: string) => {
        let trimmed = u.trim();
        if (trimmed && !trimmed.startsWith('http://') && !trimmed.startsWith('https://')) {
            return `https://${trimmed}`;
        }
        return trimmed;
    };

    onSave({
      name: name.trim(),
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      platform: finalPlatform,
      notes: notes.trim(),
      link: fixUrl(link),
      imageUrl: fixUrl(imageUrl)
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/30 dark:bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="glass-panel w-full max-w-md max-h-[90vh] overflow-y-auto flex flex-col rounded-2xl shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-5 duration-300 border border-white/40 dark:border-white/10 bg-white/80 dark:bg-gray-900/80">

        <div className="flex items-center justify-between p-5 border-b border-black/5 dark:border-white/10">
          <h2 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600 dark:from-blue-400 dark:to-indigo-400">
            {initialData ? t.editItem : t.addItem}
          </h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
            <X size={20} className="text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 flex-1">

          {/* Link Field First to encourage Auto-fill */}
          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.link}</label>
             <div className="relative flex gap-2">
                <div className="relative flex-1 group">
                    <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/60 dark:bg-black/40 border border-black/10 dark:border-white/10 text-gray-500 group-focus-within:text-blue-500 group-focus-within:border-blue-500/50 transition-all duration-300 shadow-sm backdrop-blur-sm">
                        <Paperclip size={16} />
                    </div>
                    <input 
                      type="url"
                      value={link}
                      onChange={(e) => setLink(e.target.value)}
                      className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.link ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                      placeholder="https://www.amazon.in/..."
                    />
                </div>
                <button 
                  type="button"
                  onClick={handleAutoFill}
                  disabled={!link || isFetching}
                  className="px-3 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:shadow-lg transition-all flex items-center justify-center min-w-[3rem]"
                  title="Auto-fill details from Link"
                >
                  {isFetching ? <Loader2 size={18} className="animate-spin" /> : <Zap size={18} fill="currentColor" />}
                </button>
             </div>
             {errors.link && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.link}</p>}
             {isFetching && !errors.link && (
                <p className="mt-2 text-xs text-blue-600 dark:text-blue-400 flex items-center gap-2 animate-pulse font-medium">
                   <Loader2 size={12} className="animate-spin" /> 
                   {fetchStatus}
                </p>
             )}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.name}</label>
            <input 
              type="text" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.name ? 'border-red-500 focus:ring-red-500/50' : ''}`}
              placeholder="e.g., Noise Cancelling Headphones"
            />
            {errors.name && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.name}</p>}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.category}</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c} className="dark:bg-gray-900">{t.categories[c]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.price}</label>
              <input 
                type="number" 
                min="0"
                step="0.01"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.price ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                placeholder="0.00"
              />
              {errors.price && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.price}</p>}
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.platform}</label>
            <div className="grid grid-cols-2 gap-4">
              <select 
                value={platformType}
                onChange={(e) => setPlatformType(e.target.value as EcommercePlatform)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(EcommercePlatform).map(p => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.platforms[p]}</option>
                ))}
              </select>

              {platformType === EcommercePlatform.Other && (
                <div>
                    <input 
                    type="text"
                    value={customPlatform}
                    onChange={(e) => setCustomPlatform(e.target.value)}
                    className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all animate-in fade-in slide-in-from-left-2 ${errors.platform ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                    placeholder={t.labels.specifyPlatform}
                    />
                    {errors.platform && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.platform}</p>}
                </div>
              )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.status}</label>
              <select 
                value={status}
                onChange={(e) => setStatus(e.target.value as Status)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Status).map(s => (
                  <option key={s} value={s} className="dark:bg-gray-900">{t.statuses[s]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.priority}</label>
              <select 
                value={priority}
                onChange={(e) => setPriority(e.target.value as Priority)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {(Object.values(Priority) as Priority[]).map((p) => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.priorities[p]}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.imageUrl}</label>
             <div className="relative group">
                <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/50 dark:bg-black/20 border border-black/5 dark:border-white/5 text-gray-400 group-focus-within:text-blue-500 group-focus-within:border-blue-500/30 transition-all duration-300">
                    <ImageIcon size={16} />
                </div>
                <input 
                  type="url"
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                  className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.imageUrl ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                  placeholder="https://images.com/preview.jpg"
                />
             </div>
             {errors.imageUrl && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.imageUrl}</p>}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.notes}</label>
            <textarea 
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none resize-none transition-all ${errors.notes ? 'border-red-500 focus:ring-red-500/50' : ''}`}
            />
            {errors.notes && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.notes}</p>}
          </div>

          <div className="pt-2 flex gap-3">
             <Button type="button" variant="secondary" onClick={onClose} fullWidth className="glass-panel border-0 bg-gray-200/50 hover:bg-gray-200/80 dark:bg-gray-700/50 dark:hover:bg-gray-700/80">
              {t.labels.cancel}
             </Button>
             <Button type="submit" variant="primary" fullWidth className="shadow-lg shadow-blue-500/20">
              {t.labels.save}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { WishlistItem, Category, Priority, Status, EcommercePlatform } from '../types';
import { VALIDATION_LIMITS, ALLOWED_PROTOCOLS } from '../constants';
import { useSettings } from '../context/SettingsContext';
import { useToast } from '../context/ToastContext';
import { Button } from './ui/Button';
import { X, Paperclip, AlertCircle, Image as ImageIcon, Loader2, Zap } from 'lucide-react';

interface ItemFormProps {
  initialData?: WishlistItem | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WishlistItem, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onFetchChange?: (isFetching: boolean, itemId?: string) => void;
}

interface ValidationErrors {
  name?: string;
  price?: string;
  platform?: string;
  link?: string;
  imageUrl?: string;
  notes?: string;
}

export const ItemForm: React.FC<ItemFormProps> = ({ initialData, isOpen, onClose, onSave, onFetchChange }) => {
  const { t, serpApiKey } = useSettings();
  const { showToast } = useToast();

  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>(Category.Others);
  const [price, setPrice] = useState<string>('');
  const [priority, setPriority] = useState<Priority>(Priority.Medium);
  const [status, setStatus] = useState<Status>(Status.Planned);
  const [platformType, setPlatformType] = useState<EcommercePlatform>(EcommercePlatform.Amazon);
  const [customPlatform, setCustomPlatform] = useState('');
  const [notes, setNotes] = useState('');
  const [link, setLink] = useState('');
  const [imageUrl, setImageUrl] = useState('');

  const [isFetching, setIsFetching] = useState(false);
  const [fetchStatus, setFetchStatus] = useState<string>('');

  const [errors, setErrors] = useState<ValidationErrors>({});

  const knownPlatforms = Object.values(EcommercePlatform) as string[];

  useEffect(() => {
    setErrors({});
    if (initialData) {
      setName(initialData.name);
      setCategory(initialData.category);
      setPrice(initialData.price.toString());
      setPriority(initialData.priority);
      setStatus(initialData.status);
      setNotes(initialData.notes || '');
      setLink(initialData.link || '');
      setImageUrl(initialData.imageUrl || '');

      const p = initialData.platform || EcommercePlatform.Other;
      if (knownPlatforms.includes(p) && p !== EcommercePlatform.Other) {
        setPlatformType(p as EcommercePlatform);
        setCustomPlatform('');
      } else {
        setPlatformType(EcommercePlatform.Other);
        setCustomPlatform(p === EcommercePlatform.Other ? '' : p);
      }

    } else {
      setName('');
      setCategory(Category.Others);
      setPrice('');
      setPriority(Priority.Medium);
      setStatus(Status.Planned);
      setPlatformType(EcommercePlatform.Amazon);
      setCustomPlatform('');
      setNotes('');
      setLink('');
      setImageUrl('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const detectPlatformFromUrl = (url: string): string => {
    try {
      const hostname = new URL(url).hostname.replace('www.', '');
      if (hostname.includes('amazon')) return 'Amazon';
      if (hostname.includes('flipkart')) return 'Flipkart';
      if (hostname.includes('myntra')) return 'Myntra';
      if (hostname.includes('ajio')) return 'Ajio';
      return hostname.charAt(0).toUpperCase() + hostname.slice(1).split('.')[0];
    } catch {
      return '';
    }
  };

  /**
   * Helper to parse price from string.
   * Supports: ₹, Rs, INR, $, USD, €, EUR, £, GBP
   */
  const extractPriceFromText = (text: string, requireSymbol: boolean = true): number | null => {
    if (!text) return null;
    const cleanText = text.toLowerCase().trim();

    // 0. Direct Number check (if symbol not required)
    if (!requireSymbol) {
        // Remove currency symbols and commas, check if it is a valid number
        // We preserve dots for decimals
        const numeric = cleanText.replace(/[^\d.]/g, '');
        const val = parseFloat(numeric);
        if (!isNaN(val) && val > 0) return val;
    }

    // 1. Explicit patterns (High Confidence)
    // Matches: "price: ₹100", "mrp: rs 100", "₹100 (offer)", "at ₹100", "@ ₹100"
    const explicitPattern = /(?:price|mrp|deal|offer|cost|at|@)\s*[:\-\.]?\s*(?:₹|rs\.?|inr|\$|usd|€|eur|£|gbp)?\s*([\d,]+(?:\.\d+)?)/i;
    const explicitMatch = cleanText.match(explicitPattern);
    if (explicitMatch && explicitMatch[1]) {
       return parseFloat(explicitMatch[1].replace(/,/g, ''));
    }

    // 2. Generic Currency pattern
    const currencyPattern = /(?:₹|rs\.?|inr|\$|usd|€|eur|£|gbp)\s*[:\.\-]?\s*([\d,]+(?:\.\d+)?)/gi;
    const matches = [...text.matchAll(currencyPattern)];

    for (const match of matches) {
        const priceStr = match[1].replace(/,/g, '');
        const priceVal = parseFloat(priceStr);
        const index = match.index || 0;

        // Context check: Look at 25 chars before the match to avoid "Save ₹...", "Off ₹..."
        const context = text.substring(Math.max(0, index - 25), index).toLowerCase();

        if (context.includes('save') || context.includes('off') || context.includes('discount') || context.includes('emi') || context.includes('flat')) {
            continue;
        }

        return priceVal;
    }

    return null;
  };

  const fetchWithTimeout = async (url: string, timeout = 8000) => {
      const controller = new AbortController();
      const id = setTimeout(() => controller.abort(), timeout);
      try {
        const response = await fetch(url, { signal: controller.signal });
        clearTimeout(id);
        return response;
      } catch (error) {
        clearTimeout(id);
        throw error;
      }
  };

  const handleAutoFill = async () => {
    if (!link) return;

    try {
      new URL(link);
    } catch {
      setErrors({ ...errors, link: t.validation.invalidUrl });
      return;
    }

    setIsFetching(true);
    onFetchChange?.(true, initialData?.id);
    const platform = detectPlatformFromUrl(link);
    setFetchStatus(platform ? `Connecting to ${platform}...` : 'Fetching metadata...');

    let dataFound = false;
    let detailsFound: string[] = [];
    let foundPrice: number | null = null;
    let resolvedUrl = link;

    try {
      const encodedUrl = encodeURIComponent(link);

      // STEP 1: Fetch Microlink (Resolves redirects & gets basic meta)
      // We use a timeout to prevent hanging
      const microlinkRes = await fetchWithTimeout(`https://api.microlink.io/?url=${encodedUrl}&palette=true&audio=false&video=false`);

      if (microlinkRes.ok) {
        const json = await microlinkRes.json();
        const data = json.data;

        if (data) {
            dataFound = true;

            // Capture resolved URL (Important for Short Links like amzn.in)
            if (data.url && data.url !== link) {
                resolvedUrl = data.url;
            }

            // Name
            if (data.title) {
                let cleanName = data.title.split('|')[0].split(' : ')[0].trim();
                if (cleanName.length > 80) cleanName = cleanName.substring(0, 77) + '...';
                setName(cleanName);
                if (!detailsFound.includes("Name")) detailsFound.push("Name");
            }

            // Image
            if (data.image && data.image.url) {
                setImageUrl(data.image.url);
                detailsFound.push("Image");
            }

            // Platform Detection
            if (data.publisher) {
                const lowerPub = data.publisher.toLowerCase();
                if (lowerPub.includes('amazon')) setPlatformType(EcommercePlatform.Amazon);
                else if (lowerPub.includes('flipkart')) setPlatformType(EcommercePlatform.Flipkart);
                else if (lowerPub.includes('myntra')) setPlatformType(EcommercePlatform.Myntra);
                else if (lowerPub.includes('ajio')) setPlatformType(EcommercePlatform.Ajio);
                else {
                    setPlatformType(EcommercePlatform.Other);
                    setCustomPlatform(data.publisher);
                }
            } else {
                 const p = detectPlatformFromUrl(resolvedUrl);
                 if (p) {
                    if (p === 'Amazon') setPlatformType(EcommercePlatform.Amazon);
                    else if (p === 'Flipkart') setPlatformType(EcommercePlatform.Flipkart);
                    else setPlatformType(EcommercePlatform.Other); 
                 }
            }

            // Microlink Price Fallback (Check Title & Description)
            const textsToCheck = [data.description, data.title];
            for (const text of textsToCheck) {
                const p = extractPriceFromText(text, true); 
                if (p !== null) {
                    foundPrice = p;
                    break;
                }
            }
        }
      }

      // STEP 2: Fetch SerpApi using the RESOLVED URL (if available)
      // We chain this because we want to search the "long" url for better results.
      if (serpApiKey) {
          setFetchStatus('Checking price sources...');

          // Use resolved URL from Microlink if available, otherwise original
          const searchUrl = encodeURIComponent(resolvedUrl);
          const serpRes = await fetchWithTimeout(`https://serpapi.com/search.json?engine=google&q=${searchUrl}&api_key=${serpApiKey}&num=1`);

          if (serpRes.ok) {
              const json = await serpRes.json();
              let serpPriceVal: number | null = null;

              // 1. Product Result (Direct)
              if (json.product_result?.price) {
                 serpPriceVal = extractPriceFromText(json.product_result.price.toString(), false);
              }
              // 2. Shopping Results
              else if (json.shopping_results?.[0]?.price) {
                 serpPriceVal = extractPriceFromText(json.shopping_results[0].price.toString(), false);
              }
              // 3. Knowledge Graph
              else if (json.knowledge_graph?.price) {
                 serpPriceVal = extractPriceFromText(json.knowledge_graph.price.toString(), false);
              }
              // 4. Organic Result Rich Snippet
              else if (json.organic_results?.[0]) {
                  const organic = json.organic_results[0];

                  // Check Rich Snippet Extensions
                  if (organic.rich_snippet?.top?.detected_extensions?.price) {
                      serpPriceVal = extractPriceFromText(organic.rich_snippet.top.detected_extensions.price.toString(), false);
                  }
                  // Check standard price field
                  else if (organic.price) {
                      serpPriceVal = extractPriceFromText(organic.price.toString(), false);
                  }
                  // Check Snippet Text (Aggressive fallback)
                  else if (organic.snippet) {
                      serpPriceVal = extractPriceFromText(organic.snippet, true);
                  }
                  // Check Title Text (Aggressive fallback)
                  else if (organic.title) {
                      const titlePrice = extractPriceFromText(organic.title, true);
                      if (titlePrice) serpPriceVal = titlePrice;
                  }
              }

              if (serpPriceVal !== null) {
                  foundPrice = serpPriceVal;
                  dataFound = true;
              }
          }
      }

      // Final Price Update
      if (foundPrice !== null) {
          setPrice(foundPrice.toString());
          if (!detailsFound.includes("Price")) detailsFound.push("Price");
      }

      if (dataFound) {
        const msg = detailsFound.length > 0 
            ? `Auto-filled: ${detailsFound.join(', ')}` 
            : "Metadata found. Please verify price manually.";

        // Show success if we found ANY detail, but warn if price missing
        const type = detailsFound.includes("Price") ? "success" : "success"; 
        showToast(msg, type);
      } else {
        throw new Error("No data found");
      }

    } catch (e: any) {
      console.error("Auto-fill failed", e);
      if (e.name === 'AbortError') {
         showToast("Request timed out. Please check your connection.", "error");
      } else {
         showToast(e.message || "Could not fetch details. Please fill manually.", "error");
      }
    } finally {
      setIsFetching(false);
      onFetchChange?.(false, initialData?.id);
      setFetchStatus('');
    }
  };

  const validate = (): boolean => {
    const newErrors: ValidationErrors = {};
    let isValid = true;

    if (!name.trim()) {
      newErrors.name = t.validation.required;
      isValid = false;
    } else if (name.length > VALIDATION_LIMITS.NAME_MAX_LENGTH) {
      newErrors.name = t.validation.tooLong;
      isValid = false;
    }

    // Price validation: Allow empty (0), but if typed, must be valid.
    const numPrice = parseFloat(price);
    if (price !== '' && (isNaN(numPrice) || numPrice < 0 || numPrice > VALIDATION_LIMITS.PRICE_MAX)) {
      newErrors.price = t.validation.invalidPrice;
      isValid = false;
    }

    if (platformType === EcommercePlatform.Other && customPlatform.length > VALIDATION_LIMITS.PLATFORM_MAX_LENGTH) {
      newErrors.platform = t.validation.tooLong;
      isValid = false;
    }

    const validateUrl = (urlStr: string, field: 'link' | 'imageUrl') => {
        if (!urlStr.trim()) return;
        try {
            const url = new URL(urlStr);
            if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
                newErrors[field] = t.validation.invalidUrl;
                isValid = false;
            }
        } catch (e) {
            newErrors[field] = t.validation.invalidUrl;
            isValid = false;
        }
        if (urlStr.length > VALIDATION_LIMITS.URL_MAX_LENGTH) {
            newErrors[field] = t.validation.tooLong;
            isValid = false;
        }
    };

    validateUrl(link, 'link');
    validateUrl(imageUrl, 'imageUrl');

    if (notes.length > VALIDATION_LIMITS.NOTES_MAX_LENGTH) {
      newErrors.notes = t.validation.tooLong;
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    let finalPlatform = platformType as string;
    if (platformType === EcommercePlatform.Other) {
      finalPlatform = customPlatform.trim() || EcommercePlatform.Other;
    }

    const fixUrl = (u: string) => {
        let trimmed = u.trim();
        if (trimmed && !trimmed.startsWith('http://') && !trimmed.startsWith('https://')) {
            return `https://${trimmed}`;
        }
        return trimmed;
    };

    onSave({
      name: name.trim(),
      category,
      price: parseFloat(price) || 0,
      priority,
      status,
      platform: finalPlatform,
      notes: notes.trim(),
      link: fixUrl(link),
      imageUrl: fixUrl(imageUrl)
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/30 dark:bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="glass-panel w-full max-w-md max-h-[90vh] overflow-y-auto flex flex-col rounded-2xl shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-5 duration-300 border border-white/40 dark:border-white/10 bg-white/80 dark:bg-gray-900/80">

        <div className="flex items-center justify-between p-5 border-b border-black/5 dark:border-white/10">
          <h2 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600 dark:from-blue-400 dark:to-indigo-400">
            {initialData ? t.editItem : t.addItem}
          </h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
            <X size={20} className="text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 flex-1">

          {/* Link Field First to encourage Auto-fill */}
          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.link}</label>
             <div className="relative flex gap-2">
                <div className="relative flex-1 group">
                    <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/60 dark:bg-black/40 border border-black/10 dark:border-white/10 text-gray-500 group-focus-within:text-blue-500 group-focus-within:border-blue-500/50 transition-all duration-300 shadow-sm backdrop-blur-sm">
                        <Paperclip size={16} />
                    </div>
                    <input 
                      type="url"
                      value={link}
                      onChange={(e) => setLink(e.target.value)}
                      className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.link ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                      placeholder="https://www.amazon.in/..."
                    />
                </div>
                <button 
                  type="button"
                  onClick={handleAutoFill}
                  disabled={!link || isFetching}
                  className="px-3 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:shadow-lg transition-all flex items-center justify-center min-w-[3rem]"
                  title="Auto-fill details from Link"
                >
                  {isFetching ? <Loader2 size={18} className="animate-spin" /> : <Zap size={18} fill="currentColor" />}
                </button>
             </div>
             {errors.link && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.link}</p>}
             {isFetching && !errors.link && (
                <p className="mt-2 text-xs text-blue-600 dark:text-blue-400 flex items-center gap-2 animate-pulse font-medium">
                   <Loader2 size={12} className="animate-spin" /> 
                   {fetchStatus}
                </p>
             )}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.name}</label>
            <input 
              type="text" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.name ? 'border-red-500 focus:ring-red-500/50' : ''}`}
              placeholder="e.g., Noise Cancelling Headphones"
            />
            {errors.name && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.name}</p>}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.category}</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value as Category)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c} className="dark:bg-gray-900">{t.categories[c]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.price}</label>
              <input 
                type="number" 
                min="0"
                step="0.01"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all ${errors.price ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                placeholder="0.00"
              />
              {errors.price && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.price}</p>}
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.platform}</label>
            <div className="grid grid-cols-2 gap-4">
              <select 
                value={platformType}
                onChange={(e) => setPlatformType(e.target.value as EcommercePlatform)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(EcommercePlatform).map(p => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.platforms[p]}</option>
                ))}
              </select>

              {platformType === EcommercePlatform.Other && (
                <div>
                    <input 
                    type="text"
                    value={customPlatform}
                    onChange={(e) => setCustomPlatform(e.target.value)}
                    className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all animate-in fade-in slide-in-from-left-2 ${errors.platform ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                    placeholder={t.labels.specifyPlatform}
                    />
                    {errors.platform && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.platform}</p>}
                </div>
              )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.status}</label>
              <select 
                value={status}
                onChange={(e) => setStatus(e.target.value as Status)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {Object.values(Status).map(s => (
                  <option key={s} value={s} className="dark:bg-gray-900">{t.statuses[s]}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.priority}</label>
              <select 
                value={priority}
                onChange={(e) => setPriority(e.target.value as Priority)}
                className="w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all appearance-none"
              >
                {(Object.values(Priority) as Priority[]).map((p) => (
                  <option key={p} value={p} className="dark:bg-gray-900">{t.priorities[p]}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
             <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.imageUrl}</label>
             <div className="relative group">
                <div className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-lg bg-white/50 dark:bg-black/20 border border-black/5 dark:border-white/5 text-gray-400 group-focus-within:text-blue-500 group-focus-within:border-blue-500/30 transition-all duration-300">
                    <ImageIcon size={16} />
                </div>
                <input 
                  type="url"
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                  className={`w-full pl-12 pr-3 py-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none text-sm transition-all border border-transparent hover:border-white/20 dark:hover:border-white/10 ${errors.imageUrl ? 'border-red-500 focus:ring-red-500/50' : ''}`}
                  placeholder="https://images.com/preview.jpg"
                />
             </div>
             {errors.imageUrl && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.imageUrl}</p>}
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1.5">{t.labels.notes}</label>
            <textarea 
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className={`w-full p-3 rounded-xl glass-input text-gray-900 dark:text-gray-100 placeholder-gray-400 focus:ring-2 focus:ring-blue-500/50 outline-none resize-none transition-all ${errors.notes ? 'border-red-500 focus:ring-red-500/50' : ''}`}
            />
            {errors.notes && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle size={10} /> {errors.notes}</p>}
          </div>

          <div className="pt-2 flex gap-3">
             <Button type="button" variant="secondary" onClick={onClose} fullWidth className="glass-panel border-0 bg-gray-200/50 hover:bg-gray-200/80 dark:bg-gray-700/50 dark:hover:bg-gray-700/80">
              {t.labels.cancel}
             </Button>
             <Button type="submit" variant="primary" fullWidth className="shadow-lg shadow-blue-500/20">
              {t.labels.save}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};
